{
  "name": "SmartClass Timetable",
  "description": "A minimalist, AI-powered class timetable manager with photo-to-schedule extraction and sharing capabilities.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Day {
  MONDAY = 'Monday',
  TUESDAY = 'Tuesday',
  WEDNESDAY = 'Wednesday',
  THURSDAY = 'Thursday',
  FRIDAY = 'Friday'
}

export enum BlockType {
  CLASS = 'class',
  BREAK = 'break'
}

export interface ScheduleBlock {
  id: string;
  day: Day;
  startTime: string; // HH:mm
  endTime: string;   // HH:mm
  type: BlockType;
  subject?: string;
  teacher?: string;
  room?: string;
  color?: string; // Hex or tailwind class
}

export interface Timetable {
  id: string;
  name: string;
  userId: string;
  isPublic: boolean;
  shareSlug: string;
  blocks: ScheduleBlock[];
}

export interface User {
  id: string;
  email: string;
  name: string;
  image?: string;
}

import { Day } from './types';

export const DAYS_OF_WEEK = [
  Day.MONDAY,
  Day.TUESDAY,
  Day.WEDNESDAY,
  Day.THURSDAY,
  Day.FRIDAY
];

export const START_HOUR = 8;
export const END_HOUR = 20;

export const PASTEL_COLORS = [
  { name: 'Sky', bg: 'bg-blue-100', border: 'border-blue-200', text: 'text-blue-800' },
  { name: 'Rose', bg: 'bg-rose-100', border: 'border-rose-200', text: 'text-rose-800' },
  { name: 'Emerald', bg: 'bg-emerald-100', border: 'border-emerald-200', text: 'text-emerald-800' },
  { name: 'Amber', bg: 'bg-amber-100', border: 'border-amber-200', text: 'text-amber-800' },
  { name: 'Violet', bg: 'bg-violet-100', border: 'border-violet-200', text: 'text-violet-800' },
  { name: 'Slate', bg: 'bg-slate-100', border: 'border-slate-200', text: 'text-slate-800' },
];

export const DEFAULT_COLOR = PASTEL_COLORS[0];

export const timeToMinutes = (time: string): number => {
  const [hours, minutes] = time.split(':').map(Number);
  return hours * 60 + minutes;
};

export const formatMinutesToTime = (totalMinutes: number): string => {
  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}`;
};

export const getGridPosition = (time: string) => {
  const minutes = timeToMinutes(time);
  const startMinutes = START_HOUR * 60;
  return (minutes - startMinutes) / 60;
};

import { GoogleGenAI, Type } from "@google/genai";
import { Day, BlockType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const extractTimetableFromImage = async (base64Image: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image,
            },
          },
          {
            text: "Extract the class schedule from this image. Map it to a structured JSON format. Return only the JSON. Identify the Day (Monday-Friday), Subject, Teacher, Room, and Start/End times in 24-hour format (HH:mm). If a day or time is ambiguous, do your best to infer or skip. Only include Monday to Friday."
          }
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          blocks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.STRING, enum: Object.values(Day) },
                startTime: { type: Type.STRING, description: "HH:mm format" },
                endTime: { type: Type.STRING, description: "HH:mm format" },
                subject: { type: Type.STRING },
                teacher: { type: Type.STRING },
                room: { type: Type.STRING },
                type: { type: Type.STRING, enum: Object.values(BlockType) }
              },
              required: ["day", "startTime", "endTime", "subject"]
            }
          }
        }
      }
    }
  });

  try {
    const data = JSON.parse(response.text);
    return data.blocks || [];
  } catch (error) {
    console.error("Failed to parse AI response:", error);
    return [];
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { HashRouter, Routes, Route, useNavigate, useParams } from 'react-router-dom';
import { Timetable, ScheduleBlock, Day, BlockType } from './types';
import { DAYS_OF_WEEK, START_HOUR, END_HOUR } from './constants';
import Navbar from './components/Navbar';
import TimetableGrid from './components/TimetableGrid';
import BlockModal from './components/BlockModal';
import AIUploadModal from './components/AIUploadModal';

const INITIAL_TIMETABLE: Timetable = {
  id: 'default',
  name: 'My Semester Schedule',
  userId: 'user-1',
  isPublic: false,
  shareSlug: 'my-schedule-2024',
  blocks: []
};

const Dashboard: React.FC = () => {
  const [timetable, setTimetable] = useState<Timetable>(() => {
    const saved = localStorage.getItem('smartclass_timetable');
    return saved ? JSON.parse(saved) : INITIAL_TIMETABLE;
  });
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isAIModalOpen, setIsAIModalOpen] = useState(false);
  const [editingBlock, setEditingBlock] = useState<ScheduleBlock | null>(null);

  useEffect(() => {
    localStorage.setItem('smartclass_timetable', JSON.stringify(timetable));
  }, [timetable]);

  const handleAddBlock = (day: Day, hour: number) => {
    const startTime = `${hour.toString().padStart(2, '0')}:00`;
    const endTime = `${(hour + 1).toString().padStart(2, '0')}:00`;
    setEditingBlock({
      id: '',
      day,
      startTime,
      endTime,
      type: BlockType.CLASS,
      subject: '',
      teacher: '',
      room: '',
      color: 'bg-blue-100'
    });
    setIsModalOpen(true);
  };

  const handleSaveBlock = (block: ScheduleBlock) => {
    const newBlock = block.id ? block : { ...block, id: Math.random().toString(36).substr(2, 9) };
    setTimetable(prev => ({
      ...prev,
      blocks: block.id 
        ? prev.blocks.map(b => b.id === block.id ? newBlock : b)
        : [...prev.blocks, newBlock]
    }));
    setIsModalOpen(false);
    setEditingBlock(null);
  };

  const handleDeleteBlock = (id: string) => {
    setTimetable(prev => ({
      ...prev,
      blocks: prev.blocks.filter(b => b.id !== id)
    }));
    setIsModalOpen(false);
    setEditingBlock(null);
  };

  const handleEditBlock = (block: ScheduleBlock) => {
    setEditingBlock(block);
    setIsModalOpen(true);
  };

  const handleImportBlocks = (newBlocks: Partial<ScheduleBlock>[]) => {
    const blocksWithIds = newBlocks.map(b => ({
      ...b,
      id: Math.random().toString(36).substr(2, 9),
      color: b.type === BlockType.BREAK ? 'bg-slate-100' : 'bg-blue-100'
    })) as ScheduleBlock[];

    setTimetable(prev => ({
      ...prev,
      blocks: [...prev.blocks, ...blocksWithIds]
    }));
  };

  return (
    <div className="min-h-screen pb-12">
      <Navbar 
        onOpenAI={() => setIsAIModalOpen(true)} 
        timetable={timetable}
        setTimetable={setTimetable}
      />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-8">
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden timetable-container">
          <TimetableGrid 
            blocks={timetable.blocks} 
            onAddBlock={handleAddBlock}
            onEditBlock={handleEditBlock}
          />
        </div>
      </main>

      <BlockModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSave={handleSaveBlock}
        onDelete={handleDeleteBlock}
        initialData={editingBlock}
      />

      <AIUploadModal 
        isOpen={isAIModalOpen}
        onClose={() => setIsAIModalOpen(false)}
        onConfirm={handleImportBlocks}
      />
    </div>
  );
};

const PublicView: React.FC = () => {
  const { slug } = useParams();
  const [timetable, setTimetable] = useState<Timetable | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('smartclass_timetable');
    if (saved) {
      const data = JSON.parse(saved) as Timetable;
      if (data.shareSlug === slug) {
        setTimetable(data);
      }
    }
  }, [slug]);

  if (!timetable) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen">
        <h1 className="text-2xl font-bold">Timetable not found</h1>
        <p className="text-gray-500">The link might be invalid or private.</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-12 bg-white">
      <div className="max-w-7xl mx-auto px-4 py-8">
        <div className="mb-8 text-center">
          <h1 className="text-3xl font-bold text-gray-900">{timetable.name}</h1>
          <p className="text-gray-500">Shared schedule</p>
        </div>
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden timetable-container">
          <TimetableGrid 
            blocks={timetable.blocks} 
            readOnly={true}
          />
        </div>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={<Dashboard />} />
        <Route path="/share/:slug" element={<PublicView />} />
      </Routes>
    </HashRouter>
  );
};

export default App;

