export default Navbar;

import React from 'react';
import { ScheduleBlock, Day, BlockType } from '../types';
import { DAYS_OF_WEEK, START_HOUR, END_HOUR, getGridPosition, timeToMinutes } from '../constants';

interface TimetableGridProps {
  blocks: ScheduleBlock[];
  onAddBlock?: (day: Day, hour: number) => void;
  onEditBlock?: (block: ScheduleBlock) => void;
  readOnly?: boolean;
}

const TimetableGrid: React.FC<TimetableGridProps> = ({ 
  blocks, 
  onAddBlock, 
  onEditBlock, 
  readOnly = false 
}) => {
  const hours = Array.from({ length: END_HOUR - START_HOUR + 1 }, (_, i) => START_HOUR + i);
  const rowHeight = 80; // pixels per hour

  return (
    <div className="flex flex-col min-w-[800px] bg-white">
      {/* Header */}
      <div className="flex border-b border-gray-100">
        <div className="w-20 bg-gray-50/50"></div>
        {DAYS_OF_WEEK.map(day => (
          <div key={day} className="flex-1 py-4 text-center font-semibold text-sm text-gray-600">
            {day}
          </div>
        ))}
      </div>

      {/* Grid Content */}
      <div className="relative flex">
        {/* Time Labels */}
        <div className="w-20 flex-shrink-0 bg-gray-50/50 border-r border-gray-100">
          {hours.map(hour => (
            <div key={hour} style={{ height: rowHeight }} className="relative">
              <span className="absolute -top-3 right-4 text-[10px] font-bold text-gray-400">
                {hour.toString().padStart(2, '0')}:00
              </span>
            </div>
          ))}
        </div>

        {/* Columns */}
        <div className="flex-grow flex relative">
          {DAYS_OF_WEEK.map(day => (
            <div 
              key={day} 
              className="flex-1 border-r border-gray-50 last:border-r-0 relative group"
              style={{ height: hours.length * rowHeight }}
            >
              {/* Hourly Slot Cells for clicking */}
              {!readOnly && hours.slice(0, -1).map(hour => (
                <div 
                  key={hour}
                  onClick={() => onAddBlock?.(day, hour)}
                  className="absolute left-0 right-0 hover:bg-indigo-50/30 cursor-pointer transition-colors"
                  style={{ 
                    top: (hour - START_HOUR) * rowHeight, 
                    height: rowHeight,
                    zIndex: 1
                  }}
                />
              ))}

              {/* Grid Lines */}
              {hours.map(hour => (
                <div 
                  key={hour}
                  className="absolute left-0 right-0 border-b border-gray-50 pointer-events-none"
                  style={{ top: (hour - START_HOUR) * rowHeight }}
                />
              ))}

              {/* Blocks */}
              {blocks
                .filter(b => b.day === day)
                .map(block => {
                  const startPos = getGridPosition(block.startTime);
                  const endPos = getGridPosition(block.endTime);
                  const duration = endPos - startPos;

                  return (
                    <div
                      key={block.id}
                      onClick={() => !readOnly && onEditBlock?.(block)}
                      className={`absolute left-1 right-1 rounded-xl p-2.5 shadow-sm border overflow-hidden transition-all z-10 ${
                        block.type === BlockType.BREAK 
                        ? 'border-dashed border-gray-300 bg-gray-50/50' 
                        : `${block.color} ${!readOnly ? 'hover:scale-[1.02] cursor-pointer' : ''}`
                      }`}
                      style={{
                        top: startPos * rowHeight + 4,
                        height: duration * rowHeight - 8,
                      }}
                    >
                      <div className="flex flex-col h-full">
                        <span className={`text-[11px] font-bold opacity-70 mb-0.5 ${block.type === BlockType.BREAK ? 'text-gray-400' : ''}`}>
                          {block.startTime} - {block.endTime}
                        </span>
                        <h4 className={`text-xs font-bold truncate leading-tight ${block.type === BlockType.BREAK ? 'text-gray-500' : 'text-gray-900'}`}>
                          {block.type === BlockType.BREAK ? 'Study Break' : block.subject}
                        </h4>
                        {block.room && (
                          <div className="mt-auto flex items-center gap-1 opacity-80">
                            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8,0 1111.314 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                            <span className="text-[10px] font-medium truncate">{block.room}</span>
                          </div>
                        )}
                      </div>
                    </div>
                  );
                })}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default TimetableGrid;

import React, { useState, useEffect } from 'react';
import { ScheduleBlock, Day, BlockType } from '../types';
import { PASTEL_COLORS } from '../constants';

interface BlockModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (block: ScheduleBlock) => void;
  onDelete: (id: string) => void;
  initialData: ScheduleBlock | null;
}

const BlockModal: React.FC<BlockModalProps> = ({ isOpen, onClose, onSave, onDelete, initialData }) => {
  const [formData, setFormData] = useState<ScheduleBlock>({
    id: '',
    day: Day.MONDAY,
    startTime: '09:00',
    endTime: '10:00',
    type: BlockType.CLASS,
    subject: '',
    teacher: '',
    room: '',
    color: PASTEL_COLORS[0].bg
  });

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    }
  }, [initialData]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/30 backdrop-blur-sm" onClick={onClose} />

      <div className="relative bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden p-6">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold">{formData.id ? 'Edit Block' : 'Add New Block'}</h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" fill="currentColor" viewBox="0 0 256 256"><path d="M205.66,194.34a8,8,0,0,1-11.32,11.32L128,139.31,61.66,205.66a8,8,0,0,1-11.32-11.32L116.69,128,50.34,61.66A8,8,0,0,1,61.66,50.34L128,116.69l66.34-66.35a8,8,0,0,1,11.32,11.32L139.31,128Z"></path></svg>
          </button>
        </div>

        <div className="space-y-4">
          <div className="flex p-1 bg-gray-100 rounded-xl">
            <button 
              onClick={() => setFormData({ ...formData, type: BlockType.CLASS })}
              className={`flex-1 py-1.5 rounded-lg text-sm font-medium transition-all ${formData.type === BlockType.CLASS ? 'bg-white shadow-sm' : 'text-gray-500'}`}
            >
              Class
            </button>
            <button 
              onClick={() => setFormData({ ...formData, type: BlockType.BREAK })}
              className={`flex-1 py-1.5 rounded-lg text-sm font-medium transition-all ${formData.type === BlockType.BREAK ? 'bg-white shadow-sm' : 'text-gray-500'}`}
            >
              Study Break
            </button>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-gray-400 mb-1 uppercase tracking-wider">Start Time</label>
              <input 
                type="time" 
                value={formData.startTime}
                onChange={e => setFormData({ ...formData, startTime: e.target.value })}
                className="w-full px-3 py-2 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-400 mb-1 uppercase tracking-wider">End Time</label>
              <input 
                type="time" 
                value={formData.endTime}
                onChange={e => setFormData({ ...formData, endTime: e.target.value })}
                className="w-full px-3 py-2 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>

          {formData.type === BlockType.CLASS && (
            <>
              <div>
                <label className="block text-xs font-bold text-gray-400 mb-1 uppercase tracking-wider">Subject</label>
                <input 
                  type="text" 
                  placeholder="e.g. Physics 101"
                  value={formData.subject}
                  onChange={e => setFormData({ ...formData, subject: e.target.value })}
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-gray-400 mb-1 uppercase tracking-wider">Room</label>
                  <input 
                    type="text" 
                    placeholder="B-402"
                    value={formData.room}
                    onChange={e => setFormData({ ...formData, room: e.target.value })}
                    className="w-full px-3 py-2 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-400 mb-1 uppercase tracking-wider">Teacher</label>
                  <input 
                    type="text" 
                    placeholder="Dr. Smith"
                    value={formData.teacher}
                    onChange={e => setFormData({ ...formData, teacher: e.target.value })}
                    className="w-full px-3 py-2 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-gray-400 mb-1 uppercase tracking-wider">Theme Color</label>
                <div className="flex gap-2 mt-2">
                  {PASTEL_COLORS.map(color => (
                    <button
                      key={color.bg}
                      onClick={() => setFormData({ ...formData, color: color.bg })}
                      className={`w-8 h-8 rounded-full border-2 transition-all ${color.bg} ${formData.color === color.bg ? 'border-gray-900 scale-110' : 'border-transparent'}`}
                    />
                  ))}
                </div>
              </div>
            </>
          )}

          <div className="flex gap-3 pt-6">
            {formData.id && (
              <button 
                onClick={() => onDelete(formData.id)}
                className="px-4 py-2 border border-red-100 text-red-600 rounded-xl text-sm font-semibold hover:bg-red-50 transition-colors"
              >
                Delete
              </button>
            )}
            <div className="flex-grow" />
            <button 
              onClick={onClose}
              className="px-6 py-2 bg-gray-50 text-gray-600 rounded-xl text-sm font-semibold hover:bg-gray-100 transition-colors"
            >
              Cancel
            </button>
            <button 
              onClick={() => onSave(formData)}
              disabled={formData.type === BlockType.CLASS && !formData.subject}
              className="px-6 py-2 bg-black text-white rounded-xl text-sm font-semibold hover:bg-gray-800 transition-colors disabled:opacity-30"
            >
              {formData.id ? 'Save Changes' : 'Add Block'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

