import React from 'react';
import { ScheduleBlock, Day, BlockType } from '../types.ts';
import { DAYS_OF_WEEK, START_HOUR, END_HOUR, getGridPosition } from '../constants.ts';

interface TimetableGridProps {
  blocks: ScheduleBlock[];
  onAddBlock?: (day: Day, hour: number) => void;
  onEditBlock?: (block: ScheduleBlock) => void;
  onFetchInsights?: (block: ScheduleBlock) => void;
  readOnly?: boolean;
}

const TimetableGrid: React.FC<TimetableGridProps> = ({ 
  blocks, 
  onAddBlock, 
  onEditBlock, 
  onFetchInsights,
  readOnly = false 
}) => {
  const hours = Array.from({ length: END_HOUR - START_HOUR + 1 }, (_, i) => START_HOUR + i);
  const rowHeight = 80; // pixels per hour

  const getGoogleCalendarUrl = (block: ScheduleBlock) => {
    const baseUrl = 'https://calendar.google.com/calendar/render?action=TEMPLATE';
    const text = encodeURIComponent(block.subject || 'Class');
    const location = encodeURIComponent(block.room || '');
    const details = encodeURIComponent(block.teacher ? `Teacher: ${block.teacher}` : '');

    // Simplistic date calculation - use today's date for current week demo
    const now = new Date();
    const dayIndex = Object.values(Day).indexOf(block.day) + 1; // 1 = Monday
    const currentDay = now.getDay();
    const diff = dayIndex - currentDay;
    const eventDate = new Date(now);
    eventDate.setDate(now.getDate() + diff);

    const dateStr = eventDate.toISOString().split('T')[0].replace(/-/g, '');
    const startStr = block.startTime.replace(':', '') + '00';
    const endStr = block.endTime.replace(':', '') + '00';

    return `${baseUrl}&text=${text}&location=${location}&details=${details}&dates=${dateStr}T${startStr}/${dateStr}T${endStr}`;
  };

  return (
    <div className="flex flex-col min-w-[800px] bg-white">
      {/* Header */}
      <div className="flex border-b border-gray-100">
        <div className="w-20 bg-gray-50/50"></div>
        {DAYS_OF_WEEK.map(day => (
          <div key={day} className="flex-1 py-4 text-center font-semibold text-sm text-gray-600">
            {day}
          </div>
        ))}
      </div>

      {/* Grid Content */}
      <div className="relative flex">
        {/* Time Labels */}
        <div className="w-20 flex-shrink-0 bg-gray-50/50 border-r border-gray-100">
          {hours.map(hour => (
            <div key={hour} style={{ height: rowHeight }} className="relative">
              <span className="absolute -top-3 right-4 text-[10px] font-bold text-gray-400">
                {hour.toString().padStart(2, '0')}:00
              </span>
            </div>
          ))}
        </div>

        {/* Columns */}
        <div className="flex-grow flex relative">
          {DAYS_OF_WEEK.map(day => (
            <div 
              key={day} 
              className="flex-1 border-r border-gray-50 last:border-r-0 relative group"
              style={{ height: hours.length * rowHeight }}
            >
              {/* Hourly Slot Cells for clicking */}
              {!readOnly && hours.slice(0, -1).map(hour => (
                <div 
                  key={hour}
                  onClick={() => onAddBlock?.(day, hour)}
                  className="absolute left-0 right-0 hover:bg-indigo-50/30 cursor-pointer transition-colors"
                  style={{ 
                    top: (hour - START_HOUR) * rowHeight, 
                    height: rowHeight,
                    zIndex: 1
                  }}
                />
              ))}

              {/* Grid Lines */}
              {hours.map(hour => (
                <div 
                  key={hour}
                  className="absolute left-0 right-0 border-b border-gray-50 pointer-events-none"
                  style={{ top: (hour - START_HOUR) * rowHeight }}
                />
              ))}

              {/* Blocks */}
              {blocks
                .filter(b => b.day === day)
                .map(block => {
                  const startPos = getGridPosition(block.startTime);
                  const endPos = getGridPosition(block.endTime);
                  const duration = endPos - startPos;

                  return (
                    <div
                      key={block.id}
                      className={`absolute left-1 right-1 rounded-xl p-2.5 shadow-sm border overflow-hidden transition-all z-10 group/block ${
                        block.type === BlockType.BREAK 
                        ? 'border-dashed border-gray-300 bg-gray-50/50' 
                        : `${block.color} ${!readOnly ? 'hover:shadow-md' : ''}`
                      }`}
                      style={{
                        top: startPos * rowHeight + 4,
                        height: duration * rowHeight - 8,
                      }}
                    >
                      <div className="flex flex-col h-full relative" onClick={() => !readOnly && onEditBlock?.(block)}>
                        <span className={`text-[11px] font-bold opacity-70 mb-0.5 ${block.type === BlockType.BREAK ? 'text-gray-400' : ''}`}>
                          {block.startTime} - {block.endTime}
                        </span>
                        <h4 className={`text-xs font-bold truncate leading-tight pr-8 ${block.type === BlockType.BREAK ? 'text-gray-500' : 'text-gray-900'}`}>
                          {block.type === BlockType.BREAK ? 'Study Break' : block.subject}
                        </h4>
                        {block.room && (
                          <div className="mt-auto flex items-center gap-1 opacity-80">
                            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8,0 1111.314 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                            <span className="text-[10px] font-medium truncate">{block.room}</span>
                          </div>
                        )}

                        {/* Google Integration Buttons */}
                        {block.type === BlockType.CLASS && !readOnly && (
                          <div className="absolute top-0 right-0 flex flex-col gap-1 opacity-0 group-hover/block:opacity-100 transition-opacity no-print">
                            <button 
                              onClick={(e) => { e.stopPropagation(); onFetchInsights?.(block); }}
                              className="p-1 bg-white/80 hover:bg-white rounded-md shadow-sm border border-gray-100 text-indigo-600 transition-colors"
                              title="Smart Insights (Google Search)"
                            >
                               <svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" /></svg>
                            </button>
                            <a 
                              href={getGoogleCalendarUrl(block)}
                              target="_blank"
                              rel="noopener noreferrer"
                              onClick={(e) => e.stopPropagation()}
                              className="p-1 bg-white/80 hover:bg-white rounded-md shadow-sm border border-gray-100 text-blue-600 transition-colors"
                              title="Add to Google Calendar"
                            >
                               <svg className="w-3.5 h-3.5" viewBox="0 0 24 24" fill="currentColor"><path d="M19 4h-1V2h-2v2H8V2H6v2H5c-1.11 0-1.99.9-1.99 2L3 20c0 1.1.89 2 2 2h14c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 16H5V10h14v10zm0-12H5V6h14v2zm-7 5h5v5h-5v-5z"/></svg>
                            </a>
                          </div>
                        )}
                      </div>
                    </div>
                  );
                })}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default TimetableGrid;

import React, { useState, useEffect } from 'react';

interface Printer {
  id: string;
  name: string;
  type: string;
  status: 'online' | 'offline';
  brand: 'Xiaomi' | 'HP' | 'Canon' | 'Epson' | 'Brother';
}

interface PrinterModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirmPrint: () => void;
}

const MOCK_PRINTERS: Printer[] = [
  { id: '1', name: 'Xiaomi Mi Home Printer 2', type: 'Wireless Photo', status: 'online', brand: 'Xiaomi' },
  { id: '2', name: 'HP LaserJet Pro M404n', type: 'Laser Jet', status: 'online', brand: 'HP' },
  { id: '3', name: 'Canon PIXMA TS5320', type: 'Inkjet', status: 'online', brand: 'Canon' },
  { id: '4', name: 'Brother HL-L2350DW', type: 'Laser', status: 'offline', brand: 'Brother' },
  { id: '5', name: 'Epson EcoTank ET-2720', type: 'Inkjet', status: 'online', brand: 'Epson' },
];

const PrinterModal: React.FC<PrinterModalProps> = ({ isOpen, onClose, onConfirmPrint }) => {
  const [scanning, setScanning] = useState(true);
  const [selectedPrinter, setSelectedPrinter] = useState<Printer | null>(null);
  const [connecting, setConnecting] = useState(false);
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    if (isOpen) {
      setScanning(true);
      setSelectedPrinter(null);
      setConnecting(false);
      setConnected(false);
      const timer = setTimeout(() => setScanning(false), 1500);
      return () => clearTimeout(timer);
    }
  }, [isOpen]);

  const handleConnect = (printer: Printer) => {
    if (printer.status === 'offline') return;
    setSelectedPrinter(printer);
    setConnecting(true);
    setTimeout(() => {
      setConnecting(false);
      setConnected(true);
    }, 1200);
  };

  const handleFinalPrint = () => {
    onConfirmPrint();
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={onClose} />

      <div className="relative bg-white w-full max-w-lg rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col">
        {/* Header */}
        <div className="p-8 pb-4">
          <div className="flex justify-between items-start">
            <div>
              <h2 className="text-2xl font-bold text-gray-900 mb-1">Connect to printer</h2>
              <p className="text-sm text-gray-500 font-medium">Select a device to print your timetable</p>
            </div>
            <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 256 256"><path d="M205.66,194.34a8,8,0,0,1-11.32,11.32L128,139.31,61.66,205.66a8,8,0,0,1-11.32-11.32L116.69,128,50.34,61.66A8,8,0,0,1,61.66,50.34L128,116.69l66.34-66.35a8,8,0,0,1,11.32,11.32L139.31,128Z"></path></svg>
            </button>
          </div>
        </div>

        {/* Content */}
        <div className="px-8 pb-8 flex-grow">
          {scanning ? (
            <div className="py-12 flex flex-col items-center justify-center text-center">
              <div className="relative mb-6">
                <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin" />
                <div className="absolute inset-0 flex items-center justify-center">
                   <svg className="w-6 h-6 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
                </div>
              </div>
              <p className="text-lg font-bold text-gray-900">Searching for printers...</p>
              <p className="text-sm text-gray-500">Ensure your printer is on the same Wi-Fi network</p>
            </div>
          ) : (
            <div className="space-y-3">
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Found Printers</span>
                <button onClick={() => { setScanning(true); setTimeout(() => setScanning(false), 1500); }} className="text-xs font-bold text-indigo-600 hover:text-indigo-700">Refresh</button>
              </div>

              <div className="space-y-2 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                {MOCK_PRINTERS.map((printer) => (
                  <button
                    key={printer.id}
                    disabled={printer.status === 'offline' || connecting || (connected && selectedPrinter?.id !== printer.id)}
                    onClick={() => handleConnect(printer)}
                    className={`w-full flex items-center gap-4 p-4 rounded-3xl border transition-all text-left group ${
                      selectedPrinter?.id === printer.id
                        ? 'bg-indigo-50 border-indigo-200'
                        : 'bg-white border-gray-100 hover:border-indigo-100 hover:bg-gray-50'
                    } ${printer.status === 'offline' ? 'opacity-40 grayscale cursor-not-allowed' : ''}`}
                  >
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${
                      selectedPrinter?.id === printer.id ? 'bg-white text-indigo-600 shadow-sm' : 'bg-gray-100 text-gray-500'
                    }`}>
                      {printer.brand === 'Xiaomi' ? (
                        <span className="font-bold text-lg">X</span>
                      ) : (
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
                      )}
                    </div>
                    <div className="flex-grow">
                      <h4 className="font-bold text-gray-900 group-hover:text-indigo-900">{printer.name}</h4>
                      <p className="text-xs text-gray-500 font-medium">{printer.type} • {printer.brand}</p>
                    </div>
                    <div>
                      {selectedPrinter?.id === printer.id ? (
                        connecting ? (
                          <div className="w-5 h-5 border-2 border-indigo-600 border-t-transparent rounded-full animate-spin" />
                        ) : connected ? (
                          <svg className="w-6 h-6 text-green-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                        ) : (
                           <span className="text-xs font-bold text-indigo-600">Connect</span>
                        )
                      ) : (
                        <span className={`text-[10px] font-bold uppercase tracking-wider ${printer.status === 'online' ? 'text-green-500' : 'text-gray-400'}`}>
                          {printer.status}
                        </span>
                      )}
                    </div>
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-8 pt-0 mt-auto">
          <button
            disabled={!connected}
            onClick={handleFinalPrint}
            className={`w-full py-5 rounded-[1.5rem] font-bold text-lg transition-all shadow-xl ${
              connected 
                ? 'bg-black text-white hover:bg-gray-800 shadow-gray-200' 
                : 'bg-gray-100 text-gray-400 cursor-not-allowed shadow-none'
            }`}
          >
            {connected ? `Print to ${selectedPrinter?.brand}` : 'Select a printer to continue'}
          </button>
        </div>
      </div>
    </div>
  );
};

