import { GoogleGenAI, Type } from "@google/genai";
import { Day, BlockType } from "../types.ts";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const extractTimetableFromImage = async (base64Image: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image,
            },
          },
          {
            text: "Extract the class schedule from this image. Map it to a structured JSON format. Return only the JSON. Identify the Day (Monday-Friday), Subject, Teacher, Room, and Start/End times in 24-hour format (HH:mm). If a day or time is ambiguous, do your best to infer or skip. Only include Monday to Friday."
          }
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          blocks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.STRING, enum: Object.values(Day) },
                startTime: { type: Type.STRING, description: "HH:mm format" },
                endTime: { type: Type.STRING, description: "HH:mm format" },
                subject: { type: Type.STRING },
                teacher: { type: Type.STRING },
                room: { type: Type.STRING },
                type: { type: Type.STRING, enum: Object.values(BlockType) }
              },
              required: ["day", "startTime", "endTime", "subject"]
            }
          }
        }
      }
    }
  });

  try {
    const data = JSON.parse(response.text);
    return data.blocks || [];
  } catch (error) {
    console.error("Failed to parse AI response:", error);
    return [];
  }
};

export const getSubjectInsights = async (subject: string, teacher?: string) => {
  const prompt = `Provide helpful educational insights for the class "${subject}" ${teacher ? `taught by ${teacher}` : ''}. Include common topics covered, recommended study resources, and potential online course links. Use Google Search to ensure info is up-to-date.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  return {
    text: response.text,
    sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Source',
      uri: chunk.web?.uri
    })).filter((c: any) => c.uri) || []
  };
};

export const findNearbyPrintShops = async (latitude: number, longitude: number) => {
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: "Find high-rated local printing shops, copy centers, or office supply stores nearby where I can print my documents. Include their names and links to their locations.",
    config: {
      tools: [{ googleMaps: {} }],
      toolConfig: {
        retrievalConfig: {
          latLng: {
            latitude,
            longitude
          }
        }
      }
    },
  });

  return {
    text: response.text,
    sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.maps?.title || 'Map Location',
      uri: chunk.maps?.uri
    })).filter((c: any) => c.uri) || []
  };
};

import React, { useState, useEffect, useMemo } from 'react';
import { HashRouter, Routes, Route, useParams, Navigate } from 'react-router-dom';
import { Timetable, ScheduleBlock, Day, BlockType, User } from './types.ts';
import { DAYS_OF_WEEK, START_HOUR, END_HOUR } from './constants.ts';
import Navbar from './components/Navbar.tsx';
import TimetableGrid from './components/TimetableGrid.tsx';
import BlockModal from './components/BlockModal.tsx';
import AIUploadModal from './components/AIUploadModal.tsx';
import PrinterModal from './components/PrinterModal.tsx';
import LandingPage from './components/LandingPage.tsx';
import { getSubjectInsights } from './services/geminiService.ts';

const INITIAL_TIMETABLE: Timetable = {
  id: 'default',
  name: 'My Semester Schedule',
  userId: 'user-1',
  isPublic: false,
  shareSlug: 'my-schedule-2024',
  blocks: []
};

const Dashboard: React.FC<{ user: User | null; onLogin: (u: User) => void; onLogout: () => void }> = ({ user, onLogin, onLogout }) => {
  const [timetable, setTimetable] = useState<Timetable>(() => {
    const saved = localStorage.getItem('smartclass_timetable');
    return saved ? JSON.parse(saved) : INITIAL_TIMETABLE;
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isAIModalOpen, setIsAIModalOpen] = useState(false);
  const [isPrinterModalOpen, setIsPrinterModalOpen] = useState(false);
  const [editingBlock, setEditingBlock] = useState<ScheduleBlock | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [insightData, setInsightData] = useState<{ text: string, sources: any[], subject: string } | null>(null);
  const [isInsightLoading, setIsInsightLoading] = useState(false);

  useEffect(() => {
    localStorage.setItem('smartclass_timetable', JSON.stringify(timetable));
  }, [timetable]);

  const filteredBlocks = useMemo(() => {
    if (!searchTerm.trim()) return timetable.blocks;
    const term = searchTerm.toLowerCase().trim();
    return timetable.blocks.filter(block => 
      block.subject?.toLowerCase().includes(term) ||
      block.teacher?.toLowerCase().includes(term) ||
      block.room?.toLowerCase().includes(term)
    );
  }, [timetable.blocks, searchTerm]);

  const handleAddBlock = (day: Day, hour: number) => {
    const startTime = `${hour.toString().padStart(2, '0')}:00`;
    const endTime = `${(hour + 1).toString().padStart(2, '0')}:00`;
    setEditingBlock({
      id: '',
      day,
      startTime,
      endTime,
      type: BlockType.CLASS,
      subject: '',
      teacher: '',
      room: '',
      color: 'bg-blue-100'
    });
    setIsModalOpen(true);
  };

  const handleSaveBlock = (block: ScheduleBlock) => {
    const newBlock = block.id ? block : { ...block, id: Math.random().toString(36).substr(2, 9) };
    setTimetable(prev => ({
      ...prev,
      blocks: block.id 
        ? prev.blocks.map(b => b.id === block.id ? newBlock : b)
        : [...prev.blocks, newBlock]
    }));
    setIsModalOpen(false);
    setEditingBlock(null);
  };

  const handleDeleteBlock = (id: string) => {
    setTimetable(prev => ({
      ...prev,
      blocks: prev.blocks.filter(b => b.id !== id)
    }));
    setIsModalOpen(false);
    setEditingBlock(null);
  };

  const handleEditBlock = (block: ScheduleBlock) => {
    setEditingBlock(block);
    setIsModalOpen(true);
  };

  const handleFetchInsights = async (block: ScheduleBlock) => {
    if (!block.subject) return;
    setIsInsightLoading(true);
    try {
      const data = await getSubjectInsights(block.subject, block.teacher);
      setInsightData({ ...data, subject: block.subject });
    } catch (error) {
      alert("Failed to get insights. Try again later.");
    } finally {
      setIsInsightLoading(false);
    }
  };

  const handleImportBlocks = (newBlocks: Partial<ScheduleBlock>[]) => {
    const blocksWithIds = newBlocks.map(b => ({
      ...b,
      id: Math.random().toString(36).substr(2, 9),
      color: b.type === BlockType.BREAK ? 'bg-slate-100' : 'bg-blue-100'
    })) as ScheduleBlock[];

    setTimetable(prev => ({
      ...prev,
      blocks: [...prev.blocks, ...blocksWithIds]
    }));
  };

  const handlePrintRequest = () => {
    setIsPrinterModalOpen(true);
  };

  const handleActualPrint = () => {
    window.print();
  };

  if (!user) return <Navigate to="/login" replace />;

  return (
    <div className="min-h-screen pb-12">
      <Navbar 
        onOpenAI={() => setIsAIModalOpen(true)} 
        timetable={timetable}
        setTimetable={setTimetable}
        user={user}
        onLogin={onLogin}
        onLogout={onLogout}
        onPrint={handlePrintRequest}
      />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-8">
        <div className="mb-6 flex flex-col sm:flex-row gap-4 items-center justify-between no-print">
          <div className="relative w-full max-w-md">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </div>
            <input
              type="text"
              className="block w-full pl-10 pr-10 py-2.5 bg-white border border-gray-200 rounded-2xl leading-5 text-sm placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all shadow-sm"
              placeholder="Search subject, teacher or room..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex items-center gap-2 text-sm text-gray-500 bg-white px-4 py-2 rounded-xl border border-gray-100 shadow-sm">
            <span className="font-bold text-gray-900">{filteredBlocks.length}</span>
            <span>blocks found</span>
          </div>
        </div>

        <div className="flex gap-8 items-start">
          <div className="flex-grow bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden timetable-container">
            <TimetableGrid 
              blocks={filteredBlocks} 
              onAddBlock={handleAddBlock}
              onEditBlock={handleEditBlock}
              onFetchInsights={handleFetchInsights}
            />
          </div>

          {(isInsightLoading || insightData) && (
            <div className="w-80 flex-shrink-0 bg-white border border-gray-100 rounded-2xl shadow-xl p-6 sticky top-24 no-print max-h-[calc(100vh-120px)] overflow-y-auto">
              <div className="flex justify-between items-start mb-4">
                <h3 className="font-bold text-gray-900 flex items-center gap-2">
                  <svg className="w-5 h-5 text-indigo-500" fill="currentColor" viewBox="0 0 20 20"><path d="M11 3a1 1 0 10-2 0v1a1 1 0 102 0V3zM15.657 5.757a1 1 0 00-1.414-1.414l-.707.707a1 1 0 001.414 1.414l.707-.707zM18 10a1 1 0 01-1 1h-1a1 1 0 110-2h1a1 1 0 011 1zM5.05 6.464A1 1 0 106.464 5.05l-.707-.707a1 1 0 00-1.414 1.414l.707.707zM5 10a1 1 0 01-1 1H3a1 1 0 110-2h1a1 1 0 011 1zM8 16v-1a1 1 0 112 0v1a1 1 0 11-2 0zM13.536 15.657l.707-.707a1 1 0 011.414 1.414l-.707.707a1 1 0 01-1.414-1.414zM15 10a5 5 0 11-10 0 5 5 0 0110 0z"></path></svg>
                  Insights
                </h3>
                <button onClick={() => setInsightData(null)} className="text-gray-400 hover:text-gray-600">
                   <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
                </button>
              </div>

              {isInsightLoading ? (
                <div className="py-8 flex flex-col items-center justify-center gap-3">
                  <div className="w-8 h-8 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                  <p className="text-xs font-bold text-gray-400 animate-pulse">Researching {insightData?.subject}...</p>
                </div>
              ) : (
                <div className="space-y-4">
                  <h4 className="text-lg font-bold text-indigo-900 leading-tight">{insightData?.subject}</h4>
                  <div className="text-sm text-gray-600 prose prose-sm leading-relaxed">
                    {insightData?.text.split('\n').map((line, i) => <p key={i} className="mb-2">{line}</p>)}
                  </div>
                  {insightData?.sources && insightData.sources.length > 0 && (
                    <div className="pt-4 border-t border-gray-100">
                      <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Sources Found</p>
                      <div className="space-y-2">
                        {insightData.sources.map((source, i) => (
                          <a 
                            key={i} 
                            href={source.uri} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="block p-2 bg-indigo-50 rounded-lg text-xs font-medium text-indigo-700 hover:bg-indigo-100 transition-colors truncate"
                          >
                            {source.title}
                          </a>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          )}
        </div>
      </main>

      <BlockModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSave={handleSaveBlock}
        onDelete={handleDeleteBlock}
        initialData={editingBlock}
      />

      <AIUploadModal 
        isOpen={isAIModalOpen}
        onClose={() => setIsAIModalOpen(false)}
        onConfirm={handleImportBlocks}
      />

      <PrinterModal
        isOpen={isPrinterModalOpen}
        onClose={() => setIsPrinterModalOpen(false)}
        onConfirmPrint={handleActualPrint}
      />
    </div>
  );
};

