        <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl shadow-black/5 border border-gray-100 flex flex-col items-center">
          <h2 className="text-xl font-bold text-gray-900 mb-8">Welcome to SmartClass</h2>

          <button 
