              <path d="M17.64 9.2c0-.63-.06-1.25-.16-1.84H9v3.49h4.84c-.21 1.12-.84 2.07-1.79 2.7l2.86 2.22c1.67-1.55 2.63-3.81 2.63-6.57z" fill="#4285F4"/>
              <path d="M9 18c2.43 0 4.47-.8 5.96-2.18l-2.86-2.22c-.8.53-1.82.85-3.1.85-2.39 0-4.41-1.6-5.13-3.76H.95v2.33C2.43 15.89 5.5 18 9 18z" fill="#34A853"/>
              <path d="M3.87 10.69c-.19-.53-.3-1.1-.3-1.69s.11-1.16.3-1.69V4.98H.95C.35 6.19 0 7.56 0 9s.35 2.81.95 4.02l2.92-2.33z" fill="#FBBC05"/>
              <path d="M9 3.58c1.32 0 2.5.45 3.44 1.35L15 2.47C13.47.96 11.43 0 9 0 5.5 0 2.43 2.11.95 4.98l2.92 2.33c.72-2.16 2.74-3.76 5.13-3.76z" fill="#EA4335"/>
            </svg>
            Continue with Google
