export default LandingPage;

import React, { useState, useEffect } from 'react';
import { findNearbyPrintShops } from '../services/geminiService.ts';

interface Printer {
  id: string;
  name: string;
  type: string;
  status: 'online' | 'offline';
  brand: 'Xiaomi' | 'HP' | 'Canon' | 'Epson' | 'Brother';
  connectionType: 'network' | 'bluetooth';
}

interface PrinterModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirmPrint: () => void;
}

const MOCK_PRINTERS: Printer[] = [
  { id: '1', name: 'Xiaomi Mi Home Printer 2', type: 'Wireless Photo', status: 'online', brand: 'Xiaomi', connectionType: 'network' },
  { id: '2', name: 'HP LaserJet Pro M404n', type: 'Laser Jet', status: 'online', brand: 'HP', connectionType: 'network' },
  { id: '3', name: 'Canon PIXMA TS5320', type: 'Inkjet', status: 'online', brand: 'Canon', connectionType: 'network' },
  { id: '4', name: 'Brother HL-L2350DW', type: 'Laser', status: 'offline', brand: 'Brother', connectionType: 'network' },
  { id: '5', name: 'Epson EcoTank ET-2720', type: 'Inkjet', status: 'online', brand: 'Epson', connectionType: 'network' },
  { id: '6', name: 'Xiaomi Portable Photo Printer', type: 'ZINK Bluetooth', status: 'online', brand: 'Xiaomi', connectionType: 'bluetooth' },
  { id: '7', name: 'HP Sprocket 200', type: 'Bluetooth Photo', status: 'online', brand: 'HP', connectionType: 'bluetooth' },
];

const PrinterModal: React.FC<PrinterModalProps> = ({ isOpen, onClose, onConfirmPrint }) => {
  const [scanning, setScanning] = useState(true);
  const [selectedPrinter, setSelectedPrinter] = useState<Printer | null>(null);
  const [connecting, setConnecting] = useState(false);
  const [connected, setConnected] = useState(false);
  const [searchMode, setSearchMode] = useState<'network' | 'bluetooth' | 'nearby'>('network');
  const [nearbyShops, setNearbyShops] = useState<{ text: string, sources: any[] } | null>(null);
  const [isNearbyLoading, setIsNearbyLoading] = useState(false);

  useEffect(() => {
    if (isOpen) {
      triggerScan('network');
    }
  }, [isOpen]);

  const triggerScan = (mode: 'network' | 'bluetooth' | 'nearby') => {
    setSearchMode(mode);
    setScanning(mode !== 'nearby');
    setSelectedPrinter(null);
    setConnecting(false);
    setConnected(false);

    if (mode === 'nearby') {
      handleFindNearby();
    } else {
      const timer = setTimeout(() => setScanning(false), 1500);
      return () => clearTimeout(timer);
    }
  };

  const handleFindNearby = () => {
    setIsNearbyLoading(true);
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          const data = await findNearbyPrintShops(pos.coords.latitude, pos.coords.longitude);
          setNearbyShops(data);
        } catch (err) {
          alert("Failed to find nearby shops.");
        } finally {
          setIsNearbyLoading(false);
        }
      },
      () => {
        alert("Please enable location access to find nearby shops.");
        setIsNearbyLoading(false);
      }
    );
  };

  const handleConnect = (printer: Printer) => {
    if (printer.status === 'offline') return;
    setSelectedPrinter(printer);
    setConnecting(true);
    setTimeout(() => {
      setConnecting(false);
      setConnected(true);
    }, 1200);
  };

  const handleFinalPrint = () => {
    onConfirmPrint();
    onClose();
  };

  if (!isOpen) return null;

  const filteredPrinters = MOCK_PRINTERS.filter(p => p.connectionType === searchMode);

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={onClose} />

      <div className="relative bg-white w-full max-w-lg rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col">
        {/* Header */}
        <div className="p-8 pb-4">
          <div className="flex justify-between items-start">
            <div>
              <h2 className="text-2xl font-bold text-gray-900 mb-1">
                {searchMode === 'nearby' ? 'Nearby Print Shops' : 'Connect to printer'}
              </h2>
              <p className="text-sm text-gray-500 font-medium">
                {searchMode === 'nearby' ? 'Don\'t have a printer? Find one nearby.' : 'Select a device to print your timetable'}
              </p>
            </div>
            <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 256 256"><path d="M205.66,194.34a8,8,0,0,1-11.32,11.32L128,139.31,61.66,205.66a8,8,0,0,1-11.32-11.32L116.69,128,50.34,61.66A8,8,0,0,1,61.66,50.34L128,116.69l66.34-66.35a8,8,0,0,1,11.32,11.32L139.31,128Z"></path></svg>
            </button>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="px-8 flex gap-4 mb-4">
          <button 
            onClick={() => triggerScan('network')}
            className={`text-xs font-bold pb-2 transition-all border-b-2 ${searchMode === 'network' ? 'text-indigo-600 border-indigo-600' : 'text-gray-400 border-transparent'}`}
          >
            Network
          </button>
          <button 
            onClick={() => triggerScan('bluetooth')}
            className={`text-xs font-bold pb-2 transition-all border-b-2 ${searchMode === 'bluetooth' ? 'text-blue-600 border-blue-600' : 'text-gray-400 border-transparent'}`}
          >
            Bluetooth
          </button>
          <button 
            onClick={() => triggerScan('nearby')}
            className={`text-xs font-bold pb-2 transition-all border-b-2 ${searchMode === 'nearby' ? 'text-emerald-600 border-emerald-600' : 'text-gray-400 border-transparent'}`}
          >
            Nearby Shops
          </button>
        </div>

        {/* Content */}
        <div className="px-8 pb-8 flex-grow">
          {scanning ? (
            <div className="py-12 flex flex-col items-center justify-center text-center">
              <div className="relative mb-6">
                <div className={`w-16 h-16 border-4 ${searchMode === 'bluetooth' ? 'border-blue-500' : 'border-indigo-600'} border-t-transparent rounded-full animate-spin`} />
                <div className="absolute inset-0 flex items-center justify-center">
                   {searchMode === 'bluetooth' ? (
                     <svg className="w-6 h-6 text-blue-500" fill="currentColor" viewBox="0 0 24 24"><path d="M14.88 16.38L13 18.25V14.5L14.88 16.38M13 5.75L14.88 7.63L13 9.5V5.75M17.71 7.71L12 2H11V9.17L6.41 4.59L5 6L10.59 11.59L5 17.17L6.41 18.59L11 14V21.17L12 22H17.71L12.41 16.71L17.71 11.41L12.41 6.12L17.71 7.71Z" /></svg>
                   ) : (
                     <svg className="w-6 h-6 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
                   )}
                </div>
              </div>
              <p className="text-lg font-bold text-gray-900">Searching for {searchMode} printers...</p>
              <p className="text-sm text-gray-500">{searchMode === 'bluetooth' ? 'Make sure your device is in pairing mode' : 'Ensure your printer is on the same Wi-Fi network'}</p>
            </div>
          ) : searchMode === 'nearby' ? (
            <div className="py-4">
              {isNearbyLoading ? (
                <div className="flex flex-col items-center py-12">
                  <div className="w-10 h-10 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4" />
                  <p className="text-emerald-900 font-bold animate-pulse">Locating nearby shops...</p>
                </div>
              ) : nearbyShops ? (
                <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                  <div className="text-sm text-gray-600 leading-relaxed bg-gray-50 p-4 rounded-3xl border border-gray-100 italic">
                    {nearbyShops.text}
                  </div>
                  <div className="space-y-2">
                    {nearbyShops.sources.map((source, i) => (
                      <a 
                        key={i} 
                        href={source.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center gap-3 p-4 bg-emerald-50 border border-emerald-100 rounded-[1.5rem] hover:bg-emerald-100 transition-all group"
                      >
                        <div className="w-8 h-8 rounded-full bg-white flex items-center justify-center text-emerald-600 shadow-sm">
                           <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clipRule="evenodd" /></svg>
                        </div>
                        <span className="text-sm font-bold text-emerald-800 truncate">{source.title}</span>
                        <svg className="w-4 h-4 ml-auto text-emerald-400 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"></path></svg>
                      </a>
                    ))}
                  </div>
                </div>
              ) : null}
            </div>
          ) : (
            <div className="space-y-3">
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Found Printers</span>
                <button 
                  onClick={() => triggerScan(searchMode as any)} 
                  className="text-xs font-bold text-indigo-600 hover:text-indigo-700"
                >
                  Refresh
                </button>
              </div>

              <div className="space-y-2 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                {filteredPrinters.length > 0 ? filteredPrinters.map((printer) => (
                  <button
                    key={printer.id}
                    disabled={printer.status === 'offline' || connecting || (connected && selectedPrinter?.id !== printer.id)}
                    onClick={() => handleConnect(printer)}
                    className={`w-full flex items-center gap-4 p-4 rounded-3xl border transition-all text-left group ${
                      selectedPrinter?.id === printer.id
                        ? (searchMode === 'bluetooth' ? 'bg-blue-50 border-blue-200' : 'bg-indigo-50 border-indigo-200')
                        : 'bg-white border-gray-100 hover:border-indigo-100 hover:bg-gray-50'
                    } ${printer.status === 'offline' ? 'opacity-40 grayscale cursor-not-allowed' : ''}`}
                  >
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${
                      selectedPrinter?.id === printer.id 
                        ? (searchMode === 'bluetooth' ? 'bg-white text-blue-600 shadow-sm' : 'bg-white text-indigo-600 shadow-sm')
                        : 'bg-gray-100 text-gray-500'
                    }`}>
                      {printer.brand === 'Xiaomi' ? (
                        <span className="font-bold text-lg">X</span>
                      ) : (
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
                      )}
                    </div>
                    <div className="flex-grow">
                      <h4 className="font-bold text-gray-900 group-hover:text-indigo-900">{printer.name}</h4>
                      <p className="text-xs text-gray-500 font-medium">{printer.type} • {printer.brand}</p>
                    </div>
                    <div>
                      {selectedPrinter?.id === printer.id ? (
                        connecting ? (
                          <div className={`w-5 h-5 border-2 ${searchMode === 'bluetooth' ? 'border-blue-600' : 'border-indigo-600'} border-t-transparent rounded-full animate-spin`} />
                        ) : connected ? (
                          <svg className="w-6 h-6 text-green-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                        ) : (
                           <span className={`text-xs font-bold ${searchMode === 'bluetooth' ? 'text-blue-600' : 'text-indigo-600'}`}>Connect</span>
                        )
                      ) : (
                        <span className={`text-[10px] font-bold uppercase tracking-wider ${printer.status === 'online' ? 'text-green-500' : 'text-gray-400'}`}>
                          {printer.status}
                        </span>
                      )}
                    </div>
                  </button>
                )) : (
                  <div className="py-8 text-center bg-gray-50 rounded-3xl border border-dashed border-gray-200">
                    <p className="text-sm text-gray-400 font-medium">No {searchMode} printers found</p>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-8 pt-0 mt-auto">
          {searchMode === 'nearby' ? (
            <button
              onClick={onClose}
              className="w-full py-5 rounded-[1.5rem] font-bold text-lg bg-emerald-600 text-white hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-100"
            >
              Done
            </button>
          ) : (
            <button
              disabled={!connected}
              onClick={handleFinalPrint}
              className={`w-full py-5 rounded-[1.5rem] font-bold text-lg transition-all shadow-xl ${
                connected 
                  ? 'bg-black text-white hover:bg-gray-800 shadow-gray-200' 
                  : 'bg-gray-100 text-gray-400 cursor-not-allowed shadow-none'
              }`}
            >
              {connected ? `Print to ${selectedPrinter?.brand}` : 'Select a printer to continue'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

