                </div>
              ) : (
                <div className="space-y-4">
                  <h4 className="text-lg font-bold text-indigo-900 leading-tight">{insightData?.subject}</h4>
                  <div className="text-sm text-gray-600 prose prose-sm leading-relaxed">
                    {insightData?.text.split('\n').map((line, i) => <p key={i} className="mb-2">{line}</p>)}
