                  {insightData?.sources && insightData.sources.length > 0 && (
                    <div className="pt-4 border-t border-gray-100">
                      <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Sources Found</p>
                      <div className="space-y-2">
                        {insightData.sources.map((source, i) => (
                          <a 
                            key={i} 
                            href={source.uri} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="block p-2 bg-indigo-50 rounded-lg text-xs font-medium text-indigo-700 hover:bg-indigo-100 transition-colors truncate"
                          >
                            {source.title}
