import React, { useState, useEffect } from 'react';
import { findNearbyPrintShops } from '../services/geminiService.ts';

interface Printer {
  id: string;
  name: string;
  type: string;
  status: 'online' | 'offline';
  brand: 'Xiaomi' | 'HP' | 'Canon' | 'Epson' | 'Brother';
  connectionType: 'network' | 'bluetooth';
}

interface PrinterModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirmPrint: () => void;
}

const MOCK_PRINTERS: Printer[] = [
  { id: '1', name: 'Xiaomi Mi Home Printer 2', type: 'Wireless Photo', status: 'online', brand: 'Xiaomi', connectionType: 'network' },
  { id: '2', name: 'HP LaserJet Pro M404n', type: 'Laser Jet', status: 'online', brand: 'HP', connectionType: 'network' },
  { id: '3', name: 'Canon PIXMA TS5320', type: 'Inkjet', status: 'online', brand: 'Canon', connectionType: 'network' },
  { id: '4', name: 'Brother HL-L2350DW', type: 'Laser', status: 'offline', brand: 'Brother', connectionType: 'network' },
  { id: '5', name: 'Epson EcoTank ET-2720', type: 'Inkjet', status: 'online', brand: 'Epson', connectionType: 'network' },
  { id: '6', name: 'Xiaomi Portable Photo Printer', type: 'ZINK Bluetooth', status: 'online', brand: 'Xiaomi', connectionType: 'bluetooth' },
  { id: '7', name: 'HP Sprocket 200', type: 'Bluetooth Photo', status: 'online', brand: 'HP', connectionType: 'bluetooth' },
];

const PrinterModal: React.FC<PrinterModalProps> = ({ isOpen, onClose, onConfirmPrint }) => {
  const [scanning, setScanning] = useState(true);
  const [selectedPrinter, setSelectedPrinter] = useState<Printer | null>(null);
  const [connectingStep, setConnectingStep] = useState<number>(0); // 0: idle, 1: connecting, 2: authenticating, 3: success
  const [searchMode, setSearchMode] = useState<'network' | 'bluetooth' | 'nearby'>('network');
  const [nearbyShops, setNearbyShops] = useState<{ text: string, sources: any[] } | null>(null);
  const [isNearbyLoading, setIsNearbyLoading] = useState(false);

  useEffect(() => {
    if (isOpen) {
      triggerScan('network');
    }
  }, [isOpen]);

  const triggerScan = (mode: 'network' | 'bluetooth' | 'nearby') => {
    setSearchMode(mode);
    setScanning(mode !== 'nearby');
    setSelectedPrinter(null);
    setConnectingStep(0);

    if (mode === 'nearby') {
      handleFindNearby();
    } else {
      const timer = setTimeout(() => setScanning(false), 2000);
      return () => clearTimeout(timer);
    }
  };

  const handleFindNearby = () => {
    setIsNearbyLoading(true);
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          const data = await findNearbyPrintShops(pos.coords.latitude, pos.coords.longitude);
          setNearbyShops(data);
        } catch (err) {
          alert("Failed to find nearby shops.");
        } finally {
          setIsNearbyLoading(false);
        }
      },
      () => {
        alert("Please enable location access to find nearby shops.");
        setIsNearbyLoading(false);
      }
    );
  };

  const handleConnect = (printer: Printer) => {
    if (printer.status === 'offline') return;
    setSelectedPrinter(printer);
    setConnectingStep(1);

    // Simulated connection sequence
    setTimeout(() => setConnectingStep(2), 1000); // Authenticating
    setTimeout(() => setConnectingStep(3), 2200); // Success
  };

  const handleFinalPrint = () => {
    onConfirmPrint();
    onClose();
  };

  if (!isOpen) return null;

  const filteredPrinters = MOCK_PRINTERS.filter(p => p.connectionType === searchMode);

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity" onClick={onClose} />

      <div className="relative bg-white w-full max-w-lg rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col transform transition-all duration-500 scale-100">
        {/* Header */}
        <div className="p-8 pb-4">
          <div className="flex justify-between items-start">
            <div>
              <h2 className="text-2xl font-black text-gray-900 mb-1 tracking-tight">
                {searchMode === 'nearby' ? 'Nearby Hubs' : 'Connect Printer'}
              </h2>
              <p className="text-sm text-gray-500 font-medium">
                {searchMode === 'nearby' ? 'Don\'t have a printer? Use a local shop.' : 'Select a device to link with SmartClass'}
              </p>
            </div>
            <button onClick={onClose} className="p-2.5 hover:bg-gray-100 rounded-full transition-all group active:scale-90">
              <svg className="w-6 h-6 text-gray-400 group-hover:text-gray-900" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
            </button>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="px-8 flex gap-6 mb-4 border-b border-gray-50">
          {(['network', 'bluetooth', 'nearby'] as const).map((mode) => (
            <button 
              key={mode}
              onClick={() => triggerScan(mode)}
              className={`text-[11px] font-black uppercase tracking-[0.1em] pb-3 transition-all relative ${
                searchMode === mode 
                  ? (mode === 'network' ? 'text-indigo-600' : mode === 'bluetooth' ? 'text-blue-600' : 'text-emerald-600') 
                  : 'text-gray-400 hover:text-gray-600'
              }`}
            >
              {mode}
              {searchMode === mode && (
                <span className={`absolute bottom-0 left-0 right-0 h-0.5 rounded-full ${
                  mode === 'network' ? 'bg-indigo-600' : mode === 'bluetooth' ? 'bg-blue-600' : 'bg-emerald-600'
                }`} />
              )}
            </button>
          ))}
        </div>

        {/* Content */}
        <div className="px-8 pb-8 flex-grow overflow-hidden flex flex-col">
          {scanning ? (
            <div className="py-16 flex flex-col items-center justify-center text-center">
              <div className="relative mb-8">
                {/* Ripple Effect Animation */}
                <div className={`absolute inset-0 rounded-full animate-ping opacity-20 ${searchMode === 'bluetooth' ? 'bg-blue-400' : 'bg-indigo-400'}`} style={{ animationDuration: '3s' }} />
                <div className={`absolute -inset-4 rounded-full animate-ping opacity-10 ${searchMode === 'bluetooth' ? 'bg-blue-400' : 'bg-indigo-400'}`} style={{ animationDuration: '4s' }} />

                <div className={`w-20 h-20 rounded-full border-4 ${searchMode === 'bluetooth' ? 'border-blue-500' : 'border-indigo-600'} border-t-transparent animate-spin`} />

                <div className="absolute inset-0 flex items-center justify-center scale-125">
                   {searchMode === 'bluetooth' ? (
                     <svg className="w-8 h-8 text-blue-500 animate-pulse" fill="currentColor" viewBox="0 0 24 24"><path d="M14.88 16.38L13 18.25V14.5L14.88 16.38M13 5.75L14.88 7.63L13 9.5V5.75M17.71 7.71L12 2H11V9.17L6.41 4.59L5 6L10.59 11.59L5 17.17L6.41 18.59L11 14V21.17L12 22H17.71L12.41 16.71L17.71 11.41L12.41 6.12L17.71 7.71Z" /></svg>
                   ) : (
                     <svg className="w-8 h-8 text-indigo-600 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
                   )}
                </div>
              </div>
              <h3 className="text-xl font-black text-gray-900 mb-2">Scanning for {searchMode}...</h3>
              <p className="text-sm text-gray-500 max-w-[240px] mx-auto font-medium">
                {searchMode === 'bluetooth' ? 'Ensure your portable printer is discoverable.' : 'Keep your device and printer on the same network.'}
              </p>
            </div>
          ) : searchMode === 'nearby' ? (
            <div className="py-4 h-full flex flex-col">
              {isNearbyLoading ? (
                <div className="flex flex-col items-center justify-center py-20">
                  <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-6" />
                  <p className="text-emerald-900 font-black animate-pulse uppercase tracking-widest text-xs">Locating Hubs</p>
                </div>
              ) : nearbyShops ? (
                <div className="space-y-4 max-h-[360px] overflow-y-auto pr-2 custom-scrollbar">
                  <div className="text-sm text-gray-600 leading-relaxed bg-emerald-50/30 p-5 rounded-3xl border border-emerald-100 shadow-inner">
                    <p className="font-medium text-emerald-800 italic">"Found several premium printing services in your immediate vicinity."</p>
                  </div>
                  <div className="grid gap-3">
                    {nearbyShops.sources.map((source, i) => (
                      <a 
                        key={i} 
                        href={source.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center gap-4 p-5 bg-white border border-gray-100 rounded-[1.75rem] hover:border-emerald-200 hover:bg-emerald-50/30 transition-all group shadow-sm hover:shadow-md"
                      >
                        <div className="w-12 h-12 rounded-2xl bg-emerald-100 flex items-center justify-center text-emerald-600 shadow-sm group-hover:scale-110 transition-transform">
                           <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clipRule="evenodd" /></svg>
                        </div>
                        <div className="flex-grow">
                          <span className="block text-sm font-black text-gray-900 truncate">{source.title}</span>
                          <span className="text-[10px] font-bold text-emerald-600 uppercase tracking-widest">Open Now</span>
                        </div>
                        <div className="w-8 h-8 rounded-full bg-gray-50 flex items-center justify-center group-hover:bg-white transition-colors">
                          <svg className="w-4 h-4 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"></path></svg>
                        </div>
                      </a>
                    ))}
                  </div>
                </div>
              ) : null}
            </div>
          ) : (
            <div className="space-y-4 flex flex-col h-full">
              <div className="flex items-center justify-between mb-2">
                <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Nearby Devices</span>
                <button 
                  onClick={() => triggerScan(searchMode as any)} 
                  className={`text-[10px] font-black uppercase tracking-widest transition-all ${
                    searchMode === 'bluetooth' ? 'text-blue-600 hover:text-blue-800' : 'text-indigo-600 hover:text-indigo-800'
                  }`}
                >
                  Refresh Search
                </button>
              </div>

              <div className="space-y-3 max-h-[360px] overflow-y-auto pr-2 custom-scrollbar pb-2">
                {filteredPrinters.length > 0 ? filteredPrinters.map((printer) => {
                  const isSelected = selectedPrinter?.id === printer.id;
                  const canClick = !connectingStep || isSelected;

                  return (
                    <button
                      key={printer.id}
                      disabled={printer.status === 'offline' || (connectingStep > 0 && !isSelected) || connectingStep === 3}
                      onClick={() => handleConnect(printer)}
                      className={`w-full flex items-center gap-5 p-5 rounded-[2rem] border-2 transition-all text-left relative overflow-hidden group ${
                        isSelected
                          ? (connectingStep === 3 
                              ? 'bg-green-50 border-green-200' 
                              : searchMode === 'bluetooth' ? 'bg-blue-50 border-blue-200' : 'bg-indigo-50 border-indigo-200')
                          : 'bg-white border-gray-50 hover:border-gray-200 hover:bg-gray-50/50 shadow-sm'
                      } ${printer.status === 'offline' ? 'opacity-30 grayscale cursor-not-allowed border-transparent' : ''}`}
                    >
                      {/* Brand Logo Container */}
                      <div className={`w-14 h-14 rounded-[1.25rem] flex items-center justify-center transition-all ${
                        isSelected 
                          ? (connectingStep === 3 ? 'bg-white text-green-600 shadow-sm' : 'bg-white shadow-md scale-105')
                          : 'bg-gray-100 text-gray-400 group-hover:scale-105'
                      }`}>
                        {printer.brand === 'Xiaomi' ? (
                          <span className="font-black text-2xl">X</span>
                        ) : (
                          <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
                        )}
                      </div>

                      {/* Info Area */}
                      <div className="flex-grow">
                        <h4 className={`font-black text-[15px] ${isSelected ? 'text-gray-900' : 'text-gray-800'}`}>
                          {printer.name}
                        </h4>
                        <div className="flex items-center gap-2 mt-0.5">
                          <span className={`text-[10px] font-bold uppercase tracking-widest ${isSelected ? 'text-indigo-600' : 'text-gray-400'}`}>
                            {printer.type}
                          </span>
                          <span className="w-1 h-1 bg-gray-300 rounded-full" />
                          <span className="text-[10px] font-bold text-gray-400">{printer.brand}</span>
                        </div>
                      </div>

                      {/* Status / Progress Area */}
                      <div className="min-w-[80px] flex flex-col items-end">
                        {isSelected ? (
                          <div className="flex flex-col items-end gap-1">
                            {connectingStep === 1 && <span className="text-[10px] font-black text-indigo-500 animate-pulse">CONNECTING...</span>}
                            {connectingStep === 2 && <span className="text-[10px] font-black text-indigo-600 animate-pulse">AUTHENTICATING...</span>}
                            {connectingStep === 3 ? (
                              <div className="flex items-center gap-1.5 text-green-600">
                                <span className="text-[10px] font-black">CONNECTED</span>
                                <svg className="w-5 h-5 animate-bounce-short" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                              </div>
                            ) : (
                              <div className="w-full bg-gray-200 h-1 rounded-full overflow-hidden mt-1">
                                <div 
                                  className={`h-full ${searchMode === 'bluetooth' ? 'bg-blue-600' : 'bg-indigo-600'} transition-all duration-700`} 
                                  style={{ width: connectingStep === 1 ? '40%' : connectingStep === 2 ? '80%' : '0%' }} 
                                />
                              </div>
                            )}
                          </div>
                        ) : (
                          <div className={`px-3 py-1 rounded-full text-[9px] font-black tracking-widest border ${
                            printer.status === 'online' ? 'text-green-600 border-green-100 bg-green-50/50' : 'text-gray-400 border-gray-100'
                          }`}>
                            {printer.status.toUpperCase()}
                          </div>
                        )}
                      </div>

                      {/* Success Sparkle Overlay */}
                      {isSelected && connectingStep === 3 && (
                        <div className="absolute inset-0 pointer-events-none bg-green-500/5 animate-pulse" />
                      )}
                    </button>
                  );
                }) : (
                  <div className="py-12 text-center bg-gray-50/50 rounded-[2.5rem] border-2 border-dashed border-gray-100">
                    <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center mx-auto mb-3 shadow-sm">
                       <svg className="w-6 h-6 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
                    </div>
                    <p className="text-sm text-gray-400 font-black uppercase tracking-widest">No Devices Found</p>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-8 pt-0 mt-auto">
          {searchMode === 'nearby' ? (
            <button
              onClick={onClose}
              className="w-full py-5 rounded-[1.75rem] font-black text-lg bg-emerald-600 text-white hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-100 active:scale-95"
            >
              Finish Search
            </button>
          ) : (
            <button
              disabled={connectingStep !== 3}
              onClick={handleFinalPrint}
              className={`w-full py-5 rounded-[1.75rem] font-black text-lg transition-all shadow-xl ${
                connectingStep === 3 
                  ? 'bg-black text-white hover:bg-gray-800 shadow-gray-200 active:scale-95' 
                  : 'bg-gray-100 text-gray-400 cursor-not-allowed shadow-none'
              }`}
            >
              {connectingStep === 3 ? `Print to ${selectedPrinter?.brand}` : 'Select to Connect'}
            </button>
          )}
        </div>
      </div>

      <style>{`
        @keyframes bounce-short {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-4px); }
        }
        .animate-bounce-short {
          animation: bounce-short 1s infinite;
        }
        .custom-scrollbar::-webkit-scrollbar {
          width: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #e5e7eb;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #d1d5db;
        }
      `}</style>
    </div>
  );
};

