import React, { useState, useEffect } from 'react';
import { findNearbyPrintShops } from '../services/geminiService.ts';

interface PrinterModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirmPrint: () => void;
  initialMode?: 'network' | 'bluetooth' | 'nearby';
}

const PrinterModal: React.FC<PrinterModalProps> = ({ isOpen, onClose, onConfirmPrint, initialMode = 'network' }) => {
  const [scanning, setScanning] = useState(false);
  const [searchMode, setSearchMode] = useState<'network' | 'bluetooth' | 'nearby'>(initialMode);
  const [nearbyShops, setNearbyShops] = useState<{ text: string, sources: any[] } | null>(null);
  const [isNearbyLoading, setIsNearbyLoading] = useState(false);
  const [selectedBTDevice, setSelectedBTDevice] = useState<BluetoothDevice | null>(null);
  const [btConnectionStep, setBtConnectionStep] = useState<number>(0); // 0: idle, 1: pairing, 2: ready

  useEffect(() => {
    if (isOpen) {
      handleTabChange(initialMode);
    }
  }, [isOpen, initialMode]);

  const handleTabChange = (mode: 'network' | 'bluetooth' | 'nearby') => {
    setSearchMode(mode);
    setNearbyShops(null);
    setSelectedBTDevice(null);
    setBtConnectionStep(0);
    setScanning(false);

    if (mode === 'nearby') {
      handleFindNearby();
    }
  };

  const handleFindNearby = () => {
    setIsNearbyLoading(true);
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser.");
      setIsNearbyLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          const data = await findNearbyPrintShops(pos.coords.latitude, pos.coords.longitude);
          setNearbyShops(data);
        } catch (err) {
          console.error("Maps grounding failed:", err);
        } finally {
          setIsNearbyLoading(false);
        }
      },
      (error) => {
        alert(`Location access denied: ${error.message}. Please enable location to find local hubs.`);
        setIsNearbyLoading(false);
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  };

  const handleBluetoothScan = async () => {
    if (!navigator.bluetooth) {
      alert("Web Bluetooth is not supported in this browser or environment.");
      return;
    }

    setScanning(true);
    try {
      // Requesting a real Bluetooth device. 
      // We look for any device with a printing service if possible, or any device.
      const device = await navigator.bluetooth.requestDevice({
        acceptAllDevices: true,
        // Optional: Filter for standard printing services
        // filters: [{ services: ['printing'] }] 
      });

      setSelectedBTDevice(device);
      setBtConnectionStep(1);

      // Simulate pairing sequence for the UI feedback
      setTimeout(() => setBtConnectionStep(2), 1500);
    } catch (error) {
      console.log("Bluetooth selection cancelled or failed:", error);
    } finally {
      setScanning(false);
    }
  };

  const handleSystemPrint = () => {
    onConfirmPrint(); // This triggers window.print() in the parent
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-md transition-opacity" onClick={onClose} />

      <div className="relative bg-white w-full max-w-lg rounded-[3rem] shadow-[0_32px_64px_-12px_rgba(0,0,0,0.3)] overflow-hidden flex flex-col transform transition-all duration-500">
        {/* Header */}
        <div className="p-10 pb-4">
          <div className="flex justify-between items-start">
            <div>
              <h2 className="text-3xl font-black text-gray-900 mb-1 tracking-tighter">
                {searchMode === 'nearby' ? 'Local Print Hubs' : searchMode === 'bluetooth' ? 'Bluetooth Pair' : 'Network Link'}
              </h2>
              <p className="text-sm text-gray-500 font-semibold opacity-60">
                {searchMode === 'nearby' 
