                {searchMode === 'nearby' ? 'Local Print Hubs' : searchMode === 'bluetooth' ? 'Bluetooth Pair' : 'Network Link'}
              </h2>
              <p className="text-sm text-gray-500 font-semibold opacity-60">
                {searchMode === 'nearby' 
                  ? 'Real-world locations via Google Maps' 
                  : searchMode === 'bluetooth' 
                    ? 'Connect to portable hardware via BLE' 
                    : 'Cloud & LAN connection via System Print'}
              </p>
            </div>
            <button onClick={onClose} className="p-3 hover:bg-gray-100 rounded-full transition-all group active:scale-90">
              <svg className="w-6 h-6 text-gray-400 group-hover:text-gray-900" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
            </button>
          </div>
        </div>

        {/* Navigation Tabs */}
