                      {btConnectionStep === 1 ? 'Attempting Pairing...' : 'Securely Linked'}
                    </p>
                  </div>
                  <button 
                    disabled={btConnectionStep < 2 || isPreparingPrint}
                    onClick={handleSystemPrint}
                    className={`w-full py-5 rounded-[2rem] font-black text-lg transition-all shadow-xl ${
                      btConnectionStep === 2 
                        ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-100 active:scale-95' 
