                    {scanning && <div className="absolute inset-0 rounded-[2.5rem] border-4 border-blue-600 animate-ping opacity-20" />}
                    <svg className={`w-12 h-12 ${scanning ? 'animate-pulse' : ''}`} fill="currentColor" viewBox="0 0 24 24"><path d="M14.88 16.38L13 18.25V14.5L14.88 16.38M13 5.75L14.88 7.63L13 9.5V5.75M17.71 7.71L12 2H11V9.17L6.41 4.59L5 6L10.59 11.59L5 17.17L6.41 18.59L11 14V21.17L12 22H17.71L12.41 16.71L17.71 11.41L12.41 6.12L17.71 7.71Z" /></svg>
                  </div>
                  <h3 className="text-xl font-black text-gray-900 mb-3">Discovery Mode</h3>
                  <p className="text-sm text-gray-500 font-medium max-w-[240px] mb-10 leading-relaxed">
