                  >
                    {scanning ? 'Requesting Device...' : 'Scan for Bluetooth'}
                  </button>
                </div>
              )}
            </div>
          )}

          {searchMode === 'nearby' && (
            <div className="flex flex-col h-full py-4 animate-in fade-in duration-500">
              {isNearbyLoading ? (
                <div className="flex flex-col items-center justify-center py-20 flex-grow">
                  <div className="w-14 h-14 border-[6px] border-emerald-500 border-t-transparent rounded-full animate-spin mb-8" />
                  <p className="text-emerald-900 font-black animate-pulse uppercase tracking-[0.3em] text-[10px]">Real-Time Grounding</p>
                </div>
