const INITIAL_TIMETABLE: Timetable = {
  id: 'default',
  name: 'My Semester Schedule',
  userId: 'user-1',
  isPublic: false,
  shareSlug: 'my-schedule-2024',
  blocks: [],
  exams: []
};

const Dashboard: React.FC<{ user: User | null; onLogin: (u: User) => void; onLogout: () => void }> = ({ user, onLogin, onLogout }) => {
  const [timetable, setTimetable] = useState<Timetable>(() => {
    const saved = localStorage.getItem('smartclass_timetable');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.exams) parsed.exams = [];
      return parsed;
    }
    return INITIAL_TIMETABLE;
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isAIModalOpen, setIsAIModalOpen] = useState(false);
  const [isPrinterModalOpen, setIsPrinterModalOpen] = useState(false);
  const [isExamModalOpen, setIsExamModalOpen] = useState(false);
  const [isProSettingsOpen, setIsProSettingsOpen] = useState(false);
  const [initialPrinterMode, setInitialPrinterMode] = useState<'network' | 'nearby'>('network');

  const [editingBlock, setEditingBlock] = useState<ScheduleBlock | null>(null);
  const [editingExam, setEditingExam] = useState<Exam | null>(null);

  const [searchTerm, setSearchTerm] = useState('');
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [isDarkMode, setIsDarkMode] = useState(() => localStorage.getItem('theme') === 'dark');
  const [notificationsEnabled, setNotificationsEnabled] = useState(() => localStorage.getItem('notifications') === 'true');

  const [insightData, setInsightData] = useState<{ text: string, sources: any[], subject: string } | null>(null);
  const [isInsightLoading, setIsInsightLoading] = useState(false);

  // Theme Management
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  // Notifications logic
  useEffect(() => {
    if (!notificationsEnabled || !("Notification" in window)) return;

    const checkExams = () => {
      const now = new Date();
      const todayStr = now.toISOString().split('T')[0];
      const currentTime = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;

      timetable.exams.forEach(exam => {
        if (exam.date === todayStr) {
          const [examH, examM] = exam.startTime.split(':').map(Number);
          const [nowH, nowM] = currentTime.split(':').map(Number);

          const diffMinutes = (examH * 60 + examM) - (nowH * 60 + nowM);

          // Notify 15 minutes before
          if (diffMinutes === 15) {
            new Notification("Upcoming Exam!", {
              body: `${exam.name} starts in 15 minutes at ${exam.startTime}${exam.room ? ` in ${exam.room}` : ''}.`,
              icon: '/favicon.ico'
            });
          }
        }
      });
    };

    const interval = setInterval(checkExams, 60000); // Check every minute
    return () => clearInterval(interval);
  }, [notificationsEnabled, timetable.exams]);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    localStorage.setItem('smartclass_timetable', JSON.stringify(timetable));
  }, [timetable]);

  const filteredBlocks = useMemo(() => {
    if (!searchTerm.trim()) return timetable.blocks;
    const term = searchTerm.toLowerCase().trim();
    return timetable.blocks.filter(block => 
      block.subject?.toLowerCase().includes(term) ||
      block.teacher?.toLowerCase().includes(term) ||
      block.room?.toLowerCase().includes(term)
    );
  }, [timetable.blocks, searchTerm]);

  const handleAddBlock = (day: Day, hour: number) => {
    const startTime = `${hour.toString().padStart(2, '0')}:00`;
    const endTime = `${(hour + 1).toString().padStart(2, '0')}:00`;
    setEditingBlock({
      id: '',
      day,
      startTime,
      endTime,
      type: BlockType.CLASS,
      subject: '',
      teacher: '',
      room: '',
      color: 'bg-blue-100'
    });
    setIsModalOpen(true);
  };

  const handleSaveBlock = (block: ScheduleBlock) => {
    const newBlock = block.id ? block : { ...block, id: Math.random().toString(36).substr(2, 9) };
    setTimetable(prev => ({
      ...prev,
      blocks: block.id 
        ? prev.blocks.map(b => b.id === block.id ? newBlock : b)
        : [...prev.blocks, newBlock]
    }));
    setIsModalOpen(false);
    setEditingBlock(null);
  };

  const handleDeleteBlock = (id: string) => {
    setTimetable(prev => ({
      ...prev,
      blocks: prev.blocks.filter(b => b.id !== id)
    }));
    setIsModalOpen(false);
    setEditingBlock(null);
  };

  const handleEditBlock = (block: ScheduleBlock) => {
    setEditingBlock(block);
    setIsModalOpen(true);
  };

