    const newExam = exam.id ? exam : { ...exam, id: Math.random().toString(36).substr(2, 9) };
    setTimetable(prev => ({
      ...prev,
      exams: exam.id 
        ? prev.exams.map(e => e.id === exam.id ? newExam : e)
        : [...prev.exams, newExam]
    }));
    setIsExamModalOpen(false);
    setEditingExam(null);
  };

  const handleDeleteExam = (id: string) => {
    setTimetable(prev => ({
      ...prev,
      exams: prev.exams.filter(e => e.id !== id)
    }));
    setIsExamModalOpen(false);
    setEditingExam(null);
  };

  const handleEditExam = (exam: Exam) => {
    setEditingExam(exam);
    setIsExamModalOpen(true);
  };

  const handleFetchInsights = async (block: ScheduleBlock) => {
    if (!block.subject) return;
    if (!isOnline) {
      alert("Search insights are unavailable while offline.");
      return;
    }
    setIsInsightLoading(true);
    try {
      const data = await getSubjectInsights(block.subject, block.teacher);
      setInsightData({ ...data, subject: block.subject });
    } catch (error) {
      alert("Failed to get insights. Try again later.");
    } finally {
      setIsInsightLoading(false);
    }
  };

  const handleImportBlocks = (newBlocks: Partial<ScheduleBlock>[]) => {
    const blocksWithIds = newBlocks.map(b => ({
      ...b,
      id: Math.random().toString(36).substr(2, 9),
      color: b.type === BlockType.BREAK ? 'bg-slate-100' : 'bg-blue-100'
    })) as ScheduleBlock[];

    setTimetable(prev => ({
      ...prev,
      blocks: [...prev.blocks, ...blocksWithIds]
    }));
  };

  const handlePrintRequest = (mode: 'network' | 'nearby' = 'network') => {
    setInitialPrinterMode(mode);
    setIsPrinterModalOpen(true);
  };

