                  </h3>
                  <button onClick={() => setInsightData(null)} className="text-gray-400 hover:text-gray-600">
                     <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
                  </button>
                </div>

                {isInsightLoading ? (
                  <div className="py-8 flex flex-col items-center justify-center gap-3">
                    <div className="w-8 h-8 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-xs font-bold text-gray-400 animate-pulse">Researching {insightData?.subject}...</p>
                  </div>
                ) : (
                  <div className="space-y-4">
                    <h4 className="text-lg font-bold text-indigo-900 dark:text-indigo-300 leading-tight">{insightData?.subject}</h4>
                    <div className="text-sm text-gray-600 dark:text-zinc-400 prose prose-sm leading-relaxed">
                      {insightData?.text.split('\n').map((line, i) => <p key={i} className="mb-2">{line}</p>)}
                    </div>
                  </div>
                )}
              </div>
            )}
          </aside>
        </div>
      </main>

      <BlockModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSave={handleSaveBlock}
        onDelete={handleDeleteBlock}
        initialData={editingBlock}
      />

      <AIUploadModal 
        isOpen={isAIModalOpen}
        onClose={() => setIsAIModalOpen(false)}
        onConfirm={handleImportBlocks}
      />

      <PrinterModal
        isOpen={isPrinterModalOpen}
        onClose={() => setIsPrinterModalOpen(false)}
        onConfirmPrint={handleActualPrint}
        initialMode={initialPrinterMode}
      />

      <ProSettingsModal
        isOpen={isProSettingsOpen}
        onClose={() => setIsProSettingsOpen(false)}
        isDarkMode={isDarkMode}
        toggleTheme={() => setIsDarkMode(!isDarkMode)}
        notificationsEnabled={notificationsEnabled}
        setNotificationsEnabled={setNotificationsEnabled}
      />

      <ExamModal 
        isOpen={isExamModalOpen}
        onClose={() => setIsExamModalOpen(false)}
        onSave={handleSaveExam}
        onDelete={handleDeleteExam}
        initialData={editingExam}
      />
    </div>
  );
};

const PublicView: React.FC = () => {
  const { slug } = useParams();
  const [timetable, setTimetable] = useState<Timetable | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('smartclass_timetable');
    if (saved) {
      const data = JSON.parse(saved) as Timetable;
      if (data.shareSlug === slug) {
        setTimetable(data);
      }
    }
  }, [slug]);

  if (!timetable) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen">
        <h1 className="text-2xl font-bold">Timetable not found</h1>
        <p className="text-gray-500">The link might be invalid or private.</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-12 bg-white dark:bg-zinc-950">
      <div className="max-w-7xl mx-auto px-4 py-8">
        <div className="mb-8 text-center">
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">{timetable.name}</h1>
          <p className="text-gray-500 dark:text-zinc-500">Shared schedule</p>
        </div>
        <div className="bg-white dark:bg-zinc-900 rounded-2xl shadow-sm border border-gray-100 dark:border-zinc-800 overflow-hidden timetable-container mb-12">
          <TimetableGrid 
            blocks={timetable.blocks} 
            readOnly={true}
          />
        </div>
        {timetable.exams.length > 0 && (
          <div className="max-w-3xl mx-auto">
             <h3 className="text-2xl font-bold text-gray-900 dark:text-white mb-6 flex items-center gap-2">
                <svg className="w-6 h-6 text-rose-500" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2zm-1 18H5V4h14v16zM7 17h10v-2H7v2zm0-4h10v-2H7v2zm0-4h10V7H7v2z"/></svg>
                Exam Schedule
             </h3>
             <ExamList exams={timetable.exams} readOnly={true} />
          </div>
        )}
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('smartclass_user');
    return saved ? JSON.parse(saved) : null;
  });

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('smartclass_user', JSON.stringify(u));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('smartclass_user');
  };

  return (
    <HashRouter>
      <Routes>
        <Route path="/login" element={user ? <Navigate to="/" replace /> : <LandingPage onLogin={handleLogin} />} />
        <Route path="/" element={<Dashboard user={user} onLogin={handleLogin} onLogout={handleLogout} />} />
        <Route path="/share/:slug" element={<PublicView />} />
      </Routes>
    </HashRouter>
  );
};

export default App;

