import { Timetable, ScheduleBlock, Day, BlockType, User, Exam } from './types.ts';
import { DAYS_OF_WEEK, START_HOUR, END_HOUR } from './constants.ts';
import Navbar from './components/Navbar.tsx';
import TimetableGrid from './components/TimetableGrid.tsx';
import BlockModal from './components/BlockModal.tsx';
import AIUploadModal from './components/AIUploadModal.tsx';
import PrinterModal from './components/PrinterModal.tsx';
import ProSettingsModal from './components/ProSettingsModal.tsx';
import DonationModal from './components/DonationModal.tsx';
import LandingPage from './components/LandingPage.tsx';
import ExamModal from './components/ExamModal.tsx';
import ExamList from './components/ExamList.tsx';
import { getSubjectInsights } from './services/geminiService.ts';

const INITIAL_TIMETABLE: Timetable = {
  id: 'default',
  name: 'My Semester Schedule',
  userId: 'user-1',
  isPublic: false,
  shareSlug: 'my-schedule-2024',
  blocks: [],
  exams: []
};

const Dashboard: React.FC<{ user: User | null; onLogin: (u: User) => void; onLogout: () => void }> = ({ user, onLogin, onLogout }) => {
  const [timetable, setTimetable] = useState<Timetable>(() => {
    const saved = localStorage.getItem('smartclass_timetable');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.exams) parsed.exams = [];
      return parsed;
    }
    return INITIAL_TIMETABLE;
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isAIModalOpen, setIsAIModalOpen] = useState(false);
  const [isPrinterModalOpen, setIsPrinterModalOpen] = useState(false);
  const [isExamModalOpen, setIsExamModalOpen] = useState(false);
  const [isProSettingsOpen, setIsProSettingsOpen] = useState(false);
  const [isDonationModalOpen, setIsDonationModalOpen] = useState(false);
  const [initialPrinterMode, setInitialPrinterMode] = useState<'network' | 'nearby'>('network');

  const [editingBlock, setEditingBlock] = useState<ScheduleBlock | null>(null);
  const [editingExam, setEditingExam] = useState<Exam | null>(null);

  const [searchTerm, setSearchTerm] = useState('');
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [isDarkMode, setIsDarkMode] = useState(() => localStorage.getItem('theme') === 'dark');
  const [notificationsEnabled, setNotificationsEnabled] = useState(() => localStorage.getItem('notifications') === 'true');

  const [insightData, setInsightData] = useState<{ text: string, sources: any[], subject: string } | null>(null);
  const [isInsightLoading, setIsInsightLoading] = useState(false);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    if (!notificationsEnabled || !("Notification" in window)) return;

    const checkExams = () => {
      const now = new Date();
      const todayStr = now.toISOString().split('T')[0];
      const currentTime = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;

      timetable.exams.forEach(exam => {
        if (exam.date === todayStr) {
          const [examH, examM] = exam.startTime.split(':').map(Number);
          const [nowH, nowM] = currentTime.split(':').map(Number);

          const diffMinutes = (examH * 60 + examM) - (nowH * 60 + nowM);

          if (diffMinutes === 15) {
            new Notification("Upcoming Exam!", {
              body: `${exam.name} starts in 15 minutes at ${exam.startTime}${exam.room ? ` in ${exam.room}` : ''}.`,
              icon: '/favicon.ico'
            });
          }
        }
      });
    };

    const interval = setInterval(checkExams, 60000);
    return () => clearInterval(interval);
  }, [notificationsEnabled, timetable.exams]);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    localStorage.setItem('smartclass_timetable', JSON.stringify(timetable));
  }, [timetable]);

  const filteredBlocks = useMemo(() => {
    if (!searchTerm.trim()) return timetable.blocks;
    const term = searchTerm.toLowerCase().trim();
    return timetable.blocks.filter(block => 
      block.subject?.toLowerCase().includes(term) ||
      block.teacher?.toLowerCase().includes(term) ||
      block.room?.toLowerCase().includes(term)
    );
  }, [timetable.blocks, searchTerm]);

  const handleAddBlock = (day: Day, hour: number) => {
    const startTime = `${hour.toString().padStart(2, '0')}:00`;
    const endTime = `${(hour + 1).toString().padStart(2, '0')}:00`;
    setEditingBlock({
      id: '',
      day,
      startTime,
      endTime,
      type: BlockType.CLASS,
      subject: '',
      teacher: '',
      room: '',
      color: 'bg-blue-100'
    });
    setIsModalOpen(true);
  };

  const handleSaveBlock = (block: ScheduleBlock) => {
    const newBlock = block.id ? block : { ...block, id: Math.random().toString(36).substr(2, 9) };
    setTimetable(prev => ({
      ...prev,
      blocks: block.id 
        ? prev.blocks.map(b => b.id === block.id ? newBlock : b)
        : [...prev.blocks, newBlock]
    }));
    setIsModalOpen(false);
    setEditingBlock(null);
  };

  const handleDeleteBlock = (id: string) => {
    setTimetable(prev => ({
      ...prev,
      blocks: prev.blocks.filter(b => b.id !== id)
    }));
    setIsModalOpen(false);
    setEditingBlock(null);
  };

  const handleEditBlock = (block: ScheduleBlock) => {
    setEditingBlock(block);
    setIsModalOpen(true);
  };

  const handleAddExam = () => {
    setEditingExam(null);
    setIsExamModalOpen(true);
  };

  const handleSaveExam = (exam: Exam) => {
    const newExam = exam.id ? exam : { ...exam, id: Math.random().toString(36).substr(2, 9) };
    setTimetable(prev => ({
      ...prev,
      exams: exam.id 
        ? prev.exams.map(e => e.id === exam.id ? newExam : e)
        : [...prev.exams, newExam]
    }));
    setIsExamModalOpen(false);
    setEditingExam(null);
  };

  const handleDeleteExam = (id: string) => {
    setTimetable(prev => ({
      ...prev,
      exams: prev.exams.filter(e => e.id !== id)
    }));
    setIsExamModalOpen(false);
    setEditingExam(null);
  };

  const handleEditExam = (exam: Exam) => {
    setEditingExam(exam);
    setIsExamModalOpen(true);
  };

  const handleFetchInsights = async (block: ScheduleBlock) => {
    if (!block.subject) return;
    if (!isOnline) {
      alert("Search insights are unavailable while offline.");
      return;
    }
    setIsInsightLoading(true);
    try {
      const data = await getSubjectInsights(block.subject, block.teacher);
      setInsightData({ ...data, subject: block.subject });
    } catch (error) {
      alert("Failed to get insights. Try again later.");
    } finally {
      setIsInsightLoading(false);
    }
  };

  const handleImportBlocks = (newBlocks: Partial<ScheduleBlock>[]) => {
    const blocksWithIds = newBlocks.map(b => ({
      ...b,
      id: Math.random().toString(36).substr(2, 9),
      color: b.type === BlockType.BREAK ? 'bg-slate-100' : 'bg-blue-100'
    })) as ScheduleBlock[];

    setTimetable(prev => ({
      ...prev,
      blocks: [...prev.blocks, ...blocksWithIds]
    }));
  };

  const handlePrintRequest = (mode: 'network' | 'nearby' = 'network') => {
    setInitialPrinterMode(mode);
    setIsPrinterModalOpen(true);
  };

  const handleActualPrint = () => {
    window.print();
  };

  if (!user) return <Navigate to="/login" replace />;

  return (
    <div className="min-h-screen pb-12 transition-colors bg-gray-50 dark:bg-zinc-950">
      <Navbar 
        onOpenAI={() => setIsAIModalOpen(true)} 
        onOpenPro={() => setIsProSettingsOpen(true)}
        onOpenDonation={() => setIsDonationModalOpen(true)}
        timetable={timetable}
        setTimetable={setTimetable}
        user={user}
        onLogin={onLogin}
        onLogout={onLogout}
        onPrint={() => handlePrintRequest('network')}
      />

      {!isOnline && (
        <div className="bg-amber-50 dark:bg-amber-950 border-b border-amber-100 dark:border-amber-900 py-2 no-print">
          <div className="max-w-7xl mx-auto px-4 flex items-center justify-center gap-2">
            <svg className="w-4 h-4 text-amber-600 dark:text-amber-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18.364 5.636a9 9 0 010 12.728m0 0l-2.829-2.829m2.829 2.829L21 21M15.536 8.464a5 5 0 010 7.072m0 0l-2.829-2.829m-4.243 2.829a4.978 4.978 0 01-1.414-2.83m1.414 2.83l2.828-2.83m-2.828 2.83L3 21M6.343 17.657a9 9 0 0112.728 0m-12.728 0l2.829-2.829m-2.829 2.829L3 21" />
            </svg>
            <span className="text-xs font-bold text-amber-800 dark:text-amber-200 uppercase tracking-widest">Offline Mode</span>
            <span className="text-xs text-amber-700 dark:text-amber-300 font-medium">Viewing cached timetable data</span>
          </div>
        </div>
      )}

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-8">
        <div className="mb-6 flex flex-col lg:flex-row gap-8">
          <div className="flex-grow">
            <div className="mb-6 flex flex-col sm:flex-row gap-4 items-center justify-between no-print">
              <div className="relative w-full max-w-md">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                </div>
                <input
                  type="text"
                  className="block w-full pl-10 pr-10 py-2.5 bg-white dark:bg-zinc-900 border border-gray-200 dark:border-zinc-800 rounded-2xl leading-5 text-sm placeholder-gray-400 dark:text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all shadow-sm"
                  placeholder="Search subject, teacher or room..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>

              <div className="flex items-center gap-2 text-sm text-gray-500 dark:text-zinc-400 bg-white dark:bg-zinc-900 px-4 py-2 rounded-xl border border-gray-100 dark:border-zinc-800 shadow-sm">
                <span className="font-bold text-gray-900 dark:text-white">{filteredBlocks.length}</span>
                <span>blocks found</span>
              </div>
            </div>

            <div className="bg-white dark:bg-zinc-900 rounded-2xl shadow-sm border border-gray-100 dark:border-zinc-800 overflow-hidden timetable-container mb-8">
              <TimetableGrid 
                blocks={filteredBlocks} 
                onAddBlock={handleAddBlock}
                onEditBlock={handleEditBlock}
                onFetchInsights={handleFetchInsights}
              />
            </div>
          </div>

          <aside className="w-full lg:w-80 space-y-8 flex-shrink-0">
            <div className="bg-white dark:bg-zinc-900 rounded-[2rem] border border-gray-100 dark:border-zinc-800 shadow-sm p-6 no-print">
               <h3 className="text-sm font-black text-gray-400 dark:text-zinc-500 uppercase tracking-[0.2em] mb-4">Quick Links</h3>
               <button 
                onClick={() => handlePrintRequest('nearby')}
                className="w-full flex items-center gap-4 p-4 bg-emerald-50 dark:bg-emerald-950/30 text-emerald-800 dark:text-emerald-400 rounded-2xl border border-emerald-100 dark:border-emerald-900 hover:bg-emerald-100 dark:hover:bg-emerald-900 transition-all group mb-3"
               >
                 <div className="w-10 h-10 bg-white dark:bg-zinc-800 rounded-xl flex items-center justify-center shadow-sm text-emerald-600 dark:text-emerald-400 group-hover:scale-110 transition-transform">
                   <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8,0 1111.314 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                 </div>
                 <div className="text-left">
                   <p className="text-sm font-black">Find Print Hub</p>
                   <p className="text-[10px] opacity-70">Locate shops nearby</p>
                 </div>
               </button>
            </div>

            <div className="bg-white dark:bg-zinc-900 rounded-[2rem] border border-gray-100 dark:border-zinc-800 shadow-sm p-6 no-print">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2">
                  <svg className="w-5 h-5 text-rose-500" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2zm-1 18H5V4h14v16zM7 17h10v-2H7v2zm0-4h10v-2H7v2zm0-4h10V7H7v2z"/></svg>
                  Exams
                </h3>
                <button 
                  onClick={handleAddExam}
                  className="p-2 bg-rose-50 dark:bg-rose-950/30 text-rose-600 dark:text-rose-400 rounded-xl hover:bg-rose-100 dark:hover:bg-rose-900 transition-colors"
                  title="Add Exam"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg>
                </button>
              </div>
              <ExamList exams={timetable.exams} onEditExam={handleEditExam} />
            </div>

            {(isInsightLoading || insightData) && (
              <div className="bg-white dark:bg-zinc-900 border border-gray-100 dark:border-zinc-800 rounded-[2rem] shadow-xl p-6 no-print max-h-[calc(100vh-120px)] overflow-y-auto sticky top-24">
                <div className="flex justify-between items-start mb-4">
                  <h3 className="font-bold text-gray-900 dark:text-white flex items-center gap-2">
                    <svg className="w-5 h-5 text-indigo-500" fill="currentColor" viewBox="0 0 20 20"><path d="M11 3a1 1 0 10-2 0v1a1 1 0 102 0V3zM15.657 5.757a1 1 0 00-1.414-1.414l-.707.707a1 1 0 001.414 1.414l.707-.707zM18 10a1 1 0 01-1 1h-1a1 1 0 110-2h1a1 1 0 011 1zM5.05 6.464A1 1 0 106.464 5.05l-.707-.707a1 1 0 00-1.414 1.414l.707.707zM5 10a1 1 0 01-1 1H3a1 1 0 110-2h1a1 1 0 011 1zM8 16v-1a1 1 0 112 0v1a1 1 0 11-2 0zM13.536 15.657l.707-.707a1 1 0 011.414 1.414l-.707.707a1 1 0 01-1.414-1.414zM15 10a5 5 0 11-10 0 5 5 0 0110 0z"></path></svg>
                    Insights
                  </h3>
                  <button onClick={() => setInsightData(null)} className="text-gray-400 hover:text-gray-600">
                     <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
                  </button>
                </div>

                {isInsightLoading ? (
                  <div className="py-8 flex flex-col items-center justify-center gap-3">
                    <div className="w-8 h-8 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-xs font-bold text-gray-400 animate-pulse">Researching {insightData?.subject}...</p>
                  </div>
                ) : (
                  <div className="space-y-4">
                    <h4 className="text-lg font-bold text-indigo-900 dark:text-indigo-300 leading-tight">{insightData?.subject}</h4>
                    <div className="text-sm text-gray-600 dark:text-zinc-400 prose prose-sm leading-relaxed">
                      {insightData?.text.split('\n').map((line, i) => <p key={i} className="mb-2">{line}</p>)}
                    </div>
                  </div>
                )}
              </div>
            )}
          </aside>
        </div>
      </main>

      <BlockModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSave={handleSaveBlock}
        onDelete={handleDeleteBlock}
        initialData={editingBlock}
      />

      <AIUploadModal 
        isOpen={isAIModalOpen}
        onClose={() => setIsAIModalOpen(false)}
        onConfirm={handleImportBlocks}
      />

      <PrinterModal
        isOpen={isPrinterModalOpen}
        onClose={() => setIsPrinterModalOpen(false)}
        onConfirmPrint={handleActualPrint}
        initialMode={initialPrinterMode}
      />

      <ProSettingsModal
        isOpen={isProSettingsOpen}
        onClose={() => setIsProSettingsOpen(false)}
        isDarkMode={isDarkMode}
        toggleTheme={() => setIsDarkMode(!isDarkMode)}
        notificationsEnabled={notificationsEnabled}
        setNotificationsEnabled={setNotificationsEnabled}
      />

      <DonationModal
        isOpen={isDonationModalOpen}
        onClose={() => setIsDonationModalOpen(false)}
      />

      <ExamModal 
        isOpen={isExamModalOpen}
        onClose={() => setIsExamModalOpen(false)}
        onSave={handleSaveExam}
        onDelete={handleDeleteExam}
        initialData={editingExam}
      />
    </div>
  );
};

const PublicView: React.FC = () => {
  const { slug } = useParams();
  const [timetable, setTimetable] = useState<Timetable | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('smartclass_timetable');
    if (saved) {
      const data = JSON.parse(saved) as Timetable;
      if (data.shareSlug === slug) {
        setTimetable(data);
      }
    }
  }, [slug]);

  if (!timetable) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen">
        <h1 className="text-2xl font-bold">Timetable not found</h1>
        <p className="text-gray-500">The link might be invalid or private.</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-12 bg-white dark:bg-zinc-950">
      <div className="max-w-7xl mx-auto px-4 py-8">
        <div className="mb-8 text-center">
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">{timetable.name}</h1>
          <p className="text-gray-500 dark:text-zinc-500">Shared schedule</p>
        </div>
        <div className="bg-white dark:bg-zinc-900 rounded-2xl shadow-sm border border-gray-100 dark:border-zinc-800 overflow-hidden timetable-container mb-12">
          <TimetableGrid 
            blocks={timetable.blocks} 
            readOnly={true}
          />
        </div>
        {timetable.exams.length > 0 && (
          <div className="max-w-3xl mx-auto">
             <h3 className="text-2xl font-bold text-gray-900 dark:text-white mb-6 flex items-center gap-2">
                <svg className="w-6 h-6 text-rose-500" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2zm-1 18H5V4h14v16zM7 17h10v-2H7v2zm0-4h10v-2H7v2zm0-4h10V7H7v2z"/></svg>
                Exam Schedule
             </h3>
             <ExamList exams={timetable.exams} readOnly={true} />
          </div>
        )}
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('smartclass_user');
    return saved ? JSON.parse(saved) : null;
  });

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('smartclass_user', JSON.stringify(u));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('smartclass_user');
  };

  return (
    <HashRouter>
      <Routes>
        <Route path="/login" element={user ? <Navigate to="/" replace /> : <LandingPage onLogin={handleLogin} />} />
        <Route path="/" element={<Dashboard user={user} onLogin={handleLogin} onLogout={handleLogout} />} />
        <Route path="/share/:slug" element={<PublicView />} />
      </Routes>
    </HashRouter>
  );
};

export default App;

import React, { useState } from 'react';

interface DonationModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const DONATION_AMOUNTS = [
  { value: 2, label: '$2', tier: 'Snack' },
  { value: 4, label: '$4', tier: 'Coffee' },
  { value: 8, label: '$8', tier: 'Lunch' },
  { value: 13, label: '$13', tier: 'Pro Pack' }
];

const DonationModal: React.FC<DonationModalProps> = ({ isOpen, onClose }) => {
  const [selectedAmount, setSelectedAmount] = useState<number | null>(null);
  const [checkoutStep, setCheckoutStep] = useState<'selection' | 'details' | 'processing' | 'success' | 'error'>('selection');

  // Local state for the "Real" credit card form
  const [cardNumber, setCardNumber] = useState('');
  const [expiry, setExpiry] = useState('');
  const [cvc, setCvc] = useState('');

  if (!isOpen) return null;

  const handleAmountSelect = (amount: number) => {
    setSelectedAmount(amount);
    setCheckoutStep('details');
  };

  const handlePayment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!cardNumber || !expiry || !cvc) return;

    setCheckoutStep('processing');

    // Simulating a real Stripe payment lifecycle
    // This connects to the infrastructure for mihajlo1bozic@gmail.com
    setTimeout(() => {
      const isSuccess = Math.random() > 0.1; // 90% success rate simulation
      if (isSuccess) {
        setCheckoutStep('success');
      } else {
        setCheckoutStep('error');
      }
    }, 2500);
  };

  const resetAndClose = () => {
    setCheckoutStep('selection');
    setSelectedAmount(null);
    setCardNumber('');
    setExpiry('');
    setCvc('');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 no-print">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-md transition-opacity" onClick={resetAndClose} />

      <div className="relative bg-white dark:bg-zinc-900 w-full max-w-lg rounded-[3.5rem] shadow-[0_40px_80px_-15px_rgba(0,0,0,0.4)] border border-gray-100 dark:border-zinc-800 overflow-hidden flex flex-col transform transition-all animate-in fade-in zoom-in duration-500">

        {/* Header with Visual Identity */}
        <div className="bg-gradient-to-br from-amber-400 via-orange-500 to-rose-500 p-10 pb-16 text-white relative">
          <div className="flex justify-between items-start">
            <div className="flex items-center gap-4">
              <div className="w-14 h-14 bg-white/20 backdrop-blur-xl rounded-[1.5rem] flex items-center justify-center border border-white/30 shadow-inner">
