  return (
    <div className="min-h-screen pb-12 bg-white dark:bg-zinc-950">
      <div className="max-w-7xl mx-auto px-4 py-8">
        <div className="mb-8 text-center">
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">{timetable.name}</h1>
          <p className="text-gray-500 dark:text-zinc-500">Shared schedule</p>
        </div>
        <div className="bg-white dark:bg-zinc-900 rounded-2xl shadow-sm border border-gray-100 dark:border-zinc-800 overflow-hidden timetable-container mb-12">
          <TimetableGrid 
            blocks={timetable.blocks} 
            readOnly={true}
          />
        </div>
        {timetable.exams.length > 0 && (
          <div className="max-w-3xl mx-auto mb-12">
             <h3 className="text-2xl font-bold text-gray-900 dark:text-white mb-6 flex items-center gap-2">
                <svg className="w-6 h-6 text-rose-500" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2zm-1 18H5V4h14v16zM7 17h10v-2H7v2zm0-4h10v-2H7v2zm0-4h10V7H7v2z"/></svg>
                Exam Schedule
             </h3>
             <ExamList exams={timetable.exams} readOnly={true} />
          </div>
        )}
        {timetable.grades && timetable.grades.length > 0 && (
          <div className="max-w-3xl mx-auto">
             <h3 className="text-2xl font-bold text-gray-900 dark:text-white mb-6 flex items-center gap-2">
                <svg className="w-6 h-6 text-indigo-500" fill="currentColor" viewBox="0 0 24 24"><path d="M19 3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm0 16H5V5h14v14zM7 10h2v7H7zm4-3h2v10h-2zm4 6h2v4h-2z"/></svg>
                Grades Summary
             </h3>
             <GradeList grades={timetable.grades} readOnly={true} />
          </div>
        )}
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('smartclass_user');
    return saved ? JSON.parse(saved) : null;
  });

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('smartclass_user', JSON.stringify(u));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('smartclass_user');
  };

  return (
    <HashRouter>
      <Routes>
        <Route path="/login" element={user ? <Navigate to="/" replace /> : <LandingPage onLogin={handleLogin} />} />
        <Route path="/" element={<Dashboard user={user} onLogin={handleLogin} onLogout={handleLogout} />} />
        <Route path="/share/:slug" element={<PublicView />} />
      </Routes>
    </HashRouter>
  );
};

export default App;

import React, { useState } from 'react';

interface ProSettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  isDarkMode: boolean;
  toggleTheme: () => void;
  notificationsEnabled: boolean;
  setNotificationsEnabled: (enabled: boolean) => void;
  lowGradeAlerts: boolean;
  setLowGradeAlerts: (enabled: boolean) => void;
}

const ProSettingsModal: React.FC<ProSettingsModalProps> = ({
  isOpen,
  onClose,
  isDarkMode,
  toggleTheme,
  notificationsEnabled,
  setNotificationsEnabled,
  lowGradeAlerts,
  setLowGradeAlerts,
}) => {
  const [sharing, setSharing] = useState(false);

  if (!isOpen) return null;

  const handleShare = async () => {
    setSharing(true);
    const shareData = {
      title: 'SmartClass Timetable',
      text: 'Check out SmartClass Timetable - the ultimate AI-powered student assistant!',
      url: window.location.origin,
    };

    try {
      if (navigator.share) {
        await navigator.share(shareData);
      } else {
        await navigator.clipboard.writeText(`${shareData.text} ${shareData.url}`);
        alert('App link copied to clipboard!');
      }
    } catch (err) {
      console.error('Error sharing:', err);
    } finally {
      setSharing(false);
    }
  };

  const handleToggleNotifications = async () => {
    if (!notificationsEnabled) {
      const permission = await Notification.requestPermission();
      if (permission === 'granted') {
        setNotificationsEnabled(true);
        localStorage.setItem('notifications', 'true');
      } else {
        alert("Please enable notification permissions in your browser settings to use this feature.");
      }
    } else {
      setNotificationsEnabled(false);
      localStorage.setItem('notifications', 'false');
    }
  };

  const handleToggleLowGradeAlerts = async () => {
    if (!lowGradeAlerts) {
      const permission = await Notification.requestPermission();
      if (permission === 'granted') {
        setLowGradeAlerts(true);
        localStorage.setItem('lowGradeAlerts', 'true');
      } else {
        alert("Please enable notification permissions to receive grade warnings.");
