import { GoogleGenAI, Type } from "@google/genai";
import { Day, BlockType } from "../types.ts";

export const extractTimetableFromImage = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image,
            },
          },
          {
            text: "Extract the class schedule from this image. Map it to a structured JSON format. Return only the JSON. Identify the Day (Monday-Friday), Subject, Teacher, Room, and Start/End times in 24-hour format (HH:mm). If a day or time is ambiguous, do your best to infer or skip. Only include Monday to Friday."
          }
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          blocks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.STRING, enum: Object.values(Day) },
                startTime: { type: Type.STRING, description: "HH:mm format" },
                endTime: { type: Type.STRING, description: "HH:mm format" },
                subject: { type: Type.STRING },
                teacher: { type: Type.STRING },
                room: { type: Type.STRING },
                type: { type: Type.STRING, enum: Object.values(BlockType) }
              },
              required: ["day", "startTime", "endTime", "subject"]
            }
          }
        }
      }
    }
  });

  try {
    const data = JSON.parse(response.text);
    return data.blocks || [];
  } catch (error) {
    console.error("Failed to parse AI response:", error);
    return [];
  }
};

export const getSubjectInsights = async (subject: string, teacher?: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Provide helpful educational insights for the class "${subject}" ${teacher ? `taught by ${teacher}` : ''}. Include common topics covered, recommended study resources, and potential online course links. Use Google Search to ensure info is up-to-date.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  return {
    text: response.text,
    sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Source',
      uri: chunk.web?.uri
    })).filter((c: any) => c.uri) || []
  };
};

export const findNearbyPrintShops = async (latitude: number, longitude: number) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    // Use the 2.5 series model which supports Maps grounding.
    model: "gemini-2.5-flash-native-audio-preview-09-2025",
    contents: "Find high-rated local printing shops, copy centers, or office supply stores nearby where I can print my documents. Please list the business names, their proximity, and provide direct links to their Google Maps pages. Use both search and maps data to be as accurate as possible.",
    config: {
      // Combining googleMaps and googleSearch for maximum grounding coverage.
      tools: [{ googleMaps: {} }, { googleSearch: {} }],
      toolConfig: {
        retrievalConfig: {
          latLng: {
            latitude,
            longitude
          }
        }
      }
    },
  });

  const text = response.text || "No specific shops were found in the immediate vicinity.";
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

  // Extracting both maps and web search URLs for better user choice
  const sources = chunks.map((chunk: any) => {
    if (chunk.maps) {
      return {
        title: chunk.maps.title || 'Map Location',
        uri: chunk.maps.uri,
        type: 'maps'
      };
    } else if (chunk.web) {
      return {
        title: chunk.web.title || 'Web Source',
        uri: chunk.web.uri,
        type: 'search'
      };
    }
    return null;
  }).filter(Boolean);

  return { text, sources };
};

