  const [scanning, setScanning] = useState(false);
  const [searchMode, setSearchMode] = useState<'network' | 'bluetooth' | 'nearby'>(initialMode);
  const [nearbyShops, setNearbyShops] = useState<{ text: string, sources: any[] } | null>(null);
  const [isNearbyLoading, setIsNearbyLoading] = useState(false);
  const [selectedBTDevice, setSelectedBTDevice] = useState<BluetoothDevice | null>(null);
  const [btConnectionStep, setBtConnectionStep] = useState<number>(0); // 0: idle, 1: pairing, 2: ready
  const [isPreparingPrint, setIsPreparingPrint] = useState(false);

  useEffect(() => {
    if (isOpen) {
      handleTabChange(initialMode as 'network' | 'bluetooth' | 'nearby');
      setIsPreparingPrint(false);
    }
  }, [isOpen, initialMode]);

  const handleTabChange = (mode: 'network' | 'bluetooth' | 'nearby') => {
    setSearchMode(mode);
    setNearbyShops(null);
    setSelectedBTDevice(null);
    setBtConnectionStep(0);
    setScanning(false);

    if (mode === 'nearby') {
      handleFindNearby();
    }
  };

  const handleFindNearby = () => {
    setIsNearbyLoading(true);
    setNearbyShops(null);

    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser.");
      setIsNearbyLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          const data = await findNearbyPrintShops(pos.coords.latitude, pos.coords.longitude);
          setNearbyShops(data);
        } catch (err) {
          console.error("Grounding failed:", err);
          setNearbyShops({ text: "Unable to find local shops at this moment. Please check your internet connection.", sources: [] });
        } finally {
          setIsNearbyLoading(false);
        }
      },
      (error) => {
        alert(`Location access denied: ${error.message}. Please enable location to find local hubs.`);
        setIsNearbyLoading(false);
      },
      { enableHighAccuracy: true, timeout: 8000, maximumAge: 0 }
    );
  };

  const handleBluetoothScan = async () => {
    const nav = navigator as any;
    if (!nav.bluetooth) {
      alert("Web Bluetooth is not supported in this browser or environment.");
      return;
    }

    setScanning(true);
    try {
      const device = await nav.bluetooth.requestDevice({
        acceptAllDevices: true,
      });

      setSelectedBTDevice(device);
      setBtConnectionStep(1);
      setTimeout(() => setBtConnectionStep(2), 1500);
    } catch (error) {
      console.log("Bluetooth selection cancelled or failed:", error);
    } finally {
      setScanning(false);
    }
  };

  const handleSystemPrint = () => {
    setIsPreparingPrint(true);
    // Close modal first to ensure it's not in the print capture
    onClose();
    // Wait for the modal transition to finish before triggering the blocking print dialog
    setTimeout(() => {
      onConfirmPrint();
    }, 300);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 no-print">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-md transition-opacity" onClick={onClose} />

      <div className="relative bg-white dark:bg-zinc-900 w-full max-w-lg rounded-[3rem] shadow-[0_32px_64px_-12px_rgba(0,0,0,0.3)] border border-gray-100 dark:border-zinc-800 overflow-hidden flex flex-col transform transition-all duration-500 scale-100">
        {/* Header */}
        <div className="p-8 sm:p-10 pb-4">
          <div className="flex justify-between items-start">
            <div>
              <h2 className="text-2xl sm:text-3xl font-black text-gray-900 dark:text-white mb-1 tracking-tighter">
                {searchMode === 'nearby' ? 'Local Print Hubs' : searchMode === 'bluetooth' ? 'Bluetooth Pair' : 'Network Link'}
              </h2>
              <p className="text-sm text-gray-500 dark:text-zinc-500 font-semibold opacity-60">
                {searchMode === 'nearby' 
                  ? 'Grounded via Google Maps & Search' 
                  : searchMode === 'bluetooth' 
                    ? 'Connect to portable hardware via BLE' 
                    : 'Cloud & LAN connection via System Print'}
              </p>
            </div>
            <button onClick={onClose} className="p-3 hover:bg-gray-100 dark:hover:bg-zinc-800 rounded-full transition-all group active:scale-90">
              <svg className="w-6 h-6 text-gray-400 group-hover:text-gray-900 dark:group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
            </button>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="px-8 sm:px-10 flex gap-6 sm:gap-8 mb-6 border-b border-gray-50 dark:border-zinc-800">
          {(['network', 'bluetooth', 'nearby'] as const).map((mode) => (
            <button 
              key={mode}
              onClick={() => handleTabChange(mode)}
              className={`text-[11px] sm:text-[12px] font-black uppercase tracking-[0.2em] pb-4 transition-all relative ${
                searchMode === mode 
                  ? (mode === 'network' ? 'text-indigo-600 dark:text-indigo-400' : mode === 'bluetooth' ? 'text-blue-600 dark:text-blue-400' : 'text-emerald-600 dark:text-emerald-400') 
                  : 'text-gray-400 dark:text-zinc-600 hover:text-gray-600 dark:hover:text-zinc-400'
              }`}
            >
              {mode}
              {searchMode === mode && (
                <span className={`absolute bottom-0 left-0 right-0 h-1 rounded-full ${
                  mode === 'network' ? 'bg-indigo-600 dark:bg-indigo-400' : mode === 'bluetooth' ? 'bg-blue-600 dark:bg-blue-400' : 'bg-emerald-600 dark:bg-emerald-400'
