export const findNearbyPrintShops = async (latitude: number, longitude: number) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-native-audio-preview-09-2025",
    contents: "Find high-rated local printing shops, copy centers, or office supply stores nearby where I can print my documents. Please list the business names, their proximity, and provide direct links to their Google Maps pages. Use both search and maps data to be as accurate as possible.",
    config: {
      tools: [{ googleMaps: {} }, { googleSearch: {} }],
      toolConfig: {
        retrievalConfig: {
          latLng: {
            latitude,
            longitude
          }
        }
      }
    },
  });

  const text = response.text || "No specific shops were found in the immediate vicinity.";
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

  const sources = chunks.map((chunk: any) => {
    if (chunk.maps) {
      return {
        title: chunk.maps.title || 'Map Location',
        uri: chunk.maps.uri,
        type: 'maps'
      };
    } else if (chunk.web) {
      return {
        title: chunk.web.title || 'Web Source',
        uri: chunk.web.uri,
        type: 'search'
      };
    }
    return null;
  }).filter(Boolean);

  return { text, sources };
};

