import { GoogleGenAI, Type } from "@google/genai";
import { Day, BlockType } from "../types.ts";

export const extractTimetableFromImage = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image,
            },
          },
          {
            text: "Extract the class schedule from this image. Map it to a structured JSON format. Return only the JSON. Identify the Day (Monday-Friday), Subject, Teacher, Room, and Start/End times in 24-hour format (HH:mm). If a day or time is ambiguous, do your best to infer or skip. Only include Monday to Friday."
          }
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          blocks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.STRING, enum: Object.values(Day) },
                startTime: { type: Type.STRING, description: "HH:mm format" },
                endTime: { type: Type.STRING, description: "HH:mm format" },
                subject: { type: Type.STRING },
                teacher: { type: Type.STRING },
                room: { type: Type.STRING },
                type: { type: Type.STRING, enum: Object.values(BlockType) }
              },
              required: ["day", "startTime", "endTime", "subject"]
            }
          }
        }
      }
    }
  });

  try {
    const data = JSON.parse(response.text);
    return data.blocks || [];
  } catch (error) {
    console.error("Failed to parse AI response:", error);
    return [];
  }
};

export const getSubjectInsights = async (subject: string, teacher?: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Provide helpful educational insights for the class "${subject}" ${teacher ? `taught by ${teacher}` : ''}. Include common topics covered, recommended study resources, and potential online course links. Use Google Search to ensure info is up-to-date.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  return {
    text: response.text,
    sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Source',
      uri: chunk.web?.uri
    })).filter((c: any) => c.uri) || []
  };
};

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  sources?: { title: string; uri: string }[];
}

export const sendStudyChatMessage = async (history: ChatMessage[], subject: string, grade?: number) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = `You are an elite AI Study Copilot. Your goal is to help a student improve their grades in "${subject}" ${grade ? `(Current grade: ${grade}%)` : ''}.

  Your personality is encouraging, academic, and practical. 
  When a user says they don't understand something:
  1. Explain the concept simply using analogies.
  2. Use Google Search to find the best current resources or examples.
  3. Provide 3 specific learning tips for this subject.
  4. Break down complex topics into smaller, manageable pieces.

  Always try to provide real web links to high-quality tutorials or documentation.`;

  const contents = history.map(msg => ({
    role: msg.role,
    parts: [{ text: msg.text }]
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents,
    config: {
      systemInstruction,
      tools: [{ googleSearch: {} }],
    },
  });

  const text = response.text || "I'm sorry, I couldn't process that. Let's try another topic.";
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || 'Learning Resource',
    uri: chunk.web?.uri
  })).filter((c: any) => c.uri) || [];

  return { text, sources };
};

