export const findNearbyPrintShops = async (latitude: number, longitude: number) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-native-audio-preview-09-2025",
    contents: "Find high-rated local printing shops, copy centers, or office supply stores nearby where I can print my documents. Please list the business names, their proximity, and provide direct links to their Google Maps pages. Use both search and maps data to be as accurate as possible.",
    config: {
      tools: [{ googleMaps: {} }, { googleSearch: {} }],
      toolConfig: {
        retrievalConfig: {
          latLng: {
            latitude,
            longitude
          }
        }
      }
    },
  });

  const text = response.text || "No specific shops were found in the immediate vicinity.";
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

  const sources = chunks.map((chunk: any) => {
    if (chunk.maps) {
      return {
        title: chunk.maps.title || 'Map Location',
        uri: chunk.maps.uri,
        type: 'maps'
      };
    } else if (chunk.web) {
      return {
        title: chunk.web.title || 'Web Source',
        uri: chunk.web.uri,
        type: 'search'
      };
    }
    return null;
  }).filter(Boolean);

  return { text, sources };
};

import React, { useState, useEffect, useRef } from 'react';
import { sendStudyChatMessage, ChatMessage } from '../services/geminiService.ts';

interface StudyCopilotModalProps {
  isOpen: boolean;
  onClose: () => void;
  subject: string;
  grade: number;
  data: { text: string; sources: any[] } | null;
  isLoading: boolean;
}

const StudyCopilotModal: React.FC<StudyCopilotModalProps> = ({ isOpen, onClose, subject, grade, data, isLoading }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isSending, setIsSending] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Initialize messages when data or subject changes
  useEffect(() => {
    if (isOpen && subject) {
      const initialMessage: ChatMessage = {
        role: 'model',
        text: data?.text || `Hi there! I'm your Study Copilot for ${subject}. I see we have some work to do. What specifically don't you understand or what would you like to study today?`,
        sources: data?.sources || []
      };
      setMessages([initialMessage]);
    }
  }, [isOpen, subject, data]);

  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isSending]);

  const handleSendMessage = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isSending) return;

    const userMsg: ChatMessage = { role: 'user', text: input };
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput('');
    setIsSending(true);

    try {
      const response = await sendStudyChatMessage(newMessages, subject, grade);
      setMessages([...newMessages, { role: 'model', text: response.text, sources: response.sources }]);
    } catch (err) {
      console.error(err);
      setMessages([...newMessages, { role: 'model', text: "I'm sorry, I hit a snag while researching. Can you try rephrasing that?" }]);
    } finally {
      setIsSending(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-md transition-opacity" onClick={onClose} />

      <div className="relative bg-white dark:bg-zinc-950 w-full max-w-3xl h-[85vh] rounded-[3rem] shadow-[0_32px_64px_-12px_rgba(0,0,0,0.3)] border border-gray-100 dark:border-zinc-800 overflow-hidden flex flex-col transform transition-all animate-in fade-in zoom-in duration-300">

        {/* Header */}
        <div className="bg-gradient-to-br from-indigo-600 via-violet-600 to-fuchsia-600 p-6 text-white relative shrink-0">
          <div className="flex justify-between items-center relative z-10">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center border border-white/20 shadow-lg">
                <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
              </div>
              <div>
                <h2 className="text-xl font-black tracking-tight leading-none">{subject} Study Copilot</h2>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-[10px] font-black uppercase tracking-widest opacity-80">Interactive Session</span>
                  <div className="w-1 h-1 bg-green-400 rounded-full animate-pulse" />
                </div>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <div className="hidden xs:flex flex-col items-end mr-2">
                <span className="text-[10px] font-black uppercase tracking-tighter opacity-60">Status</span>
                <span className="text-xs font-bold">{grade > 0 ? `Target: Improve ${grade}%` : 'Strategic Coaching'}</span>
              </div>
              <button onClick={onClose} className="p-2 bg-white/10 hover:bg-white/20 rounded-full transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
              </button>
            </div>
          </div>
        </div>

        {/* Chat Area */}
        <div 
          ref={scrollRef}
          className="flex-grow overflow-y-auto p-6 space-y-6 custom-scrollbar bg-gray-50/30 dark:bg-zinc-900/10"
        >
          {messages.map((msg, i) => (
            <div 
              key={i} 
              className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}
            >
              <div 
                className={`max-w-[85%] p-5 rounded-[2rem] text-sm font-medium leading-relaxed shadow-sm ${
                  msg.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-tr-none' 
                    : 'bg-white dark:bg-zinc-800 text-gray-800 dark:text-zinc-100 rounded-tl-none border border-gray-100 dark:border-zinc-700'
                }`}
              >
                <div className="whitespace-pre-wrap">{msg.text}</div>

