export const verifyGoogleCredentials = async (email: string, password: string): Promise<User> => {
  // Simulate network latency and server-side processing
  await new Promise(resolve => setTimeout(resolve, 2500));

  // Basic client-side format validation
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(email)) {
    throw new Error("Invalid email format.");
  }

  if (password.length < 6) {
    throw new Error("Authentication failed: Password must be at least 6 characters.");
  }

  // Check for common demo account or "real" simulation logic
  // For the purpose of this advanced app, we accept any valid-looking input 
  // to simulate a successful check against "real Google services"

  return {
    id: `google-${Math.random().toString(36).substr(2, 9)}`,
    email: email,
    name: email.split('@')[0].charAt(0).toUpperCase() + email.split('@')[0].slice(1),
    picture: `https://picsum.photos/seed/${email}/100/100`,
    given_name: email.split('@')[0]
  };
