export const sendStudyChatMessage = async (history: ChatMessage[], currentSubject: string, timetableContext: Timetable) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Create a context snapshot for the AI
  const gradeSummary = timetableContext.grades
    .map(g => `${g.subject}: ${g.value}% (${g.note || 'Exam'})`)
    .join(', ');

  const systemInstruction = `You are an elite AI Study Copilot with long-term memory. 

  USER CONTEXT:
  - Current focus subject: ${currentSubject}
  - Full Grade Profile: ${gradeSummary || 'No grades logged yet.'}
  - Total Classes: ${timetableContext.blocks.length}

  Your goal is to help the student improve. You remember past session details provided in the history.
  When explaining:
  1. Use Socratic questioning to guide them.
  2. Use Google Search to find real-world practice problems.
  3. If they are failing a specific subject in their profile, gently remind them of the importance of balancing their time.

  Maintain an encouraging, mentor-like persona.`;

  const contents = history.slice(-10).map(msg => ({ // Send last 10 messages for context window efficiency
    role: msg.role,
    parts: [{ text: msg.text }]
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents,
    config: {
      systemInstruction,
      tools: [{ googleSearch: {} }],
    },
  });

  const text = response.text || "I'm processing that... let's look at it from another angle.";
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || 'Resource',
    uri: chunk.web?.uri
  })).filter((c: any) => c.uri) || [];

  return { text, sources };
};

