      alert("Strategic planning requires an internet connection.");
      return;
    }
    setStudyHelpData({ text: '', sources: [], subject: 'Holistic Academic Strategy', grade: 100 });
    setIsStudyCopilotOpen(true);
    setIsStudyHelpLoading(true);
