import { GoogleGenAI, Type } from "@google/genai";
import { Day, BlockType, Timetable, ChatMessage } from "../types.ts";

export const extractTimetableFromImage = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image,
            },
          },
          {
            text: "Extract the class schedule from this image. Map it to a structured JSON format. Return only the JSON. Identify the Day (Monday-Friday), Subject, Teacher, Room, and Start/End times in 24-hour format (HH:mm). If a day or time is ambiguous, do your best to infer or skip. Only include Monday to Friday."
          }
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          blocks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.STRING, enum: Object.values(Day) },
                startTime: { type: Type.STRING, description: "HH:mm format" },
                endTime: { type: Type.STRING, description: "HH:mm format" },
                subject: { type: Type.STRING },
                teacher: { type: Type.STRING },
                room: { type: Type.STRING },
                type: { type: Type.STRING, enum: Object.values(BlockType) }
              },
              required: ["day", "startTime", "endTime", "subject"]
            }
          }
        }
      }
    }
  });

  try {
    const data = JSON.parse(response.text);
    return data.blocks || [];
  } catch (error) {
    console.error("Failed to parse AI response:", error);
    return [];
  }
};

export const getSubjectInsights = async (subject: string, teacher?: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Provide helpful educational insights for the class "${subject}" ${teacher ? `taught by ${teacher}` : ''}. Include common topics covered, recommended study resources, and potential online course links. Use Google Search to ensure info is up-to-date.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  return {
    text: response.text,
    sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Source',
      uri: chunk.web?.uri
    })).filter((c: any) => c.uri) || []
  };
};

export const sendStudyChatMessage = async (history: ChatMessage[], currentSubject: string, timetableContext: Timetable) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Create a context snapshot for the AI
  const gradeSummary = timetableContext.grades
    .map(g => `${g.subject}: ${g.value}% (${g.note || 'Exam'})`)
    .join(', ');

  const systemInstruction = `You are an elite AI Study Copilot with long-term memory. 

  USER CONTEXT:
  - Current focus subject: ${currentSubject}
  - Full Grade Profile: ${gradeSummary || 'No grades logged yet.'}
  - Total Classes: ${timetableContext.blocks.length}

  Your goal is to help the student improve. You remember past session details provided in the history.
  When explaining:
  1. Use Socratic questioning to guide them.
  2. Use Google Search to find real-world practice problems.
  3. If they are failing a specific subject in their profile, gently remind them of the importance of balancing their time.

  Maintain an encouraging, mentor-like persona.`;

  const contents = history.slice(-10).map(msg => ({ // Send last 10 messages for context window efficiency
    role: msg.role,
    parts: [{ text: msg.text }]
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents,
    config: {
      systemInstruction,
      tools: [{ googleSearch: {} }],
    },
  });

  const text = response.text || "I'm processing that... let's look at it from another angle.";
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || 'Resource',
    uri: chunk.web?.uri
  })).filter((c: any) => c.uri) || [];

  return { text, sources };
};

