                onClick={() => { onClose(); setTimeout(onConfirmPrint, 300); }}
                className="w-full py-4 bg-black dark:bg-indigo-600 text-white rounded-2xl font-black text-lg hover:scale-[1.02] active:scale-95 transition-all shadow-xl"
            >
                Generate Print View
            </button>
            <button 
                onClick={onClose}
                className="mt-4 text-sm font-bold text-gray-400 hover:text-gray-600 dark:text-zinc-500 dark:hover:text-zinc-300 uppercase tracking-widest transition-colors"
            >
                Cancel
            </button>
        </div>
      </div>
    </div>
  );
};

